/**
 * Controls where clue scrolls are placed relative to other priority task drops.
 */
public enum ClueScrollPriority {
    /** Above the other priority task drops (very top of the menu). */
    BEFORE,
    /** Below the other priority task drops, but still above non-priority items. */
    AFTER,
    /** No special placement; follows the "Show clue scrolls" option and normal classification. */
    OFF
}

package com.slayerdropprioritizer;

/**
 * Minimum tier that triggers a priority-drop notification.
 */
public enum NotifyTier {
    /** Notify for any priority drop (task, value, rarity, clue, custom list). */
    ALL_PRIORITY,
    /** Notify only for drops in the Rare or Ultra-Rare rarity tier. */
    RARE,
    /** Notify only for drops in the Ultra-Rare rarity tier. */
    ULTRA_RARE
}

package com.slayerdropprioritizer;

import java.util.Map;
import java.util.Set;

/**
 * On-disk representation of a resolved NPC drop table.
 * Serialized as JSON via Gson under .runelite/slayer-drop-prioritizer/.
 *
 * Rarity values are stored as the effective denominator N (i.e. a 1/N chance), so a
 * Wiki rarity of "3/128" is stored as ~42.67 rather than 128.
 */
class CachedDropTable {
    /** Bumped whenever the parsing logic changes so older caches are discarded. */
    static final int CURRENT_VERSION = 2;

    int version;
    long timestamp;
    Set<String> drops;
    Map<String, Double> rarities;

    CachedDropTable() {
    }

    CachedDropTable(int version, long timestamp, Set<String> drops, Map<String, Double> rarities) {
        this.version = version;
        this.timestamp = timestamp;
        this.drops = drops;
        this.rarities = rarities;
    }
}

package com.slayerdropprioritizer;

/**
 * Controls whether clue scrolls may be hidden.
 */
public enum ClueScrollDisplay {
    /** Clue scrolls are never hidden, regardless of the display mode. */
    ALWAYS,
    /** Clue scrolls follow the normal display mode rules. */
    MODE,
    /** Clue scrolls are always hidden in HIDE modes. */
    NEVER
}

