	{
		allTrackers = List.of(
			new MaidenTracker(client, this),
			new BloatTracker(client, this),
			new NyloTracker(client, this),
			new SoteTracker(client, this),
			new XarpusTracker(client, this),
			new VerzikTracker(client, this)
		);
	}

	@Override
	protected void shutDown()
	{
		resetAll();
		resetAllInfoBoxes();
		allTrackers = null;
	}

	@Subscribe
	public void onConfigChanged(ConfigChanged event)
	{
		if (!"theatreofbloodstats".equals(event.getGroup()) || infoBoxes.isEmpty())
		{
			return;
		}

		switch (event.getKey())
		{
			case "infoBoxTooltip":
			case "infoBoxTooltipDmg":
			case "infoBoxTooltipHealed":
			case "infoBoxTooltipSplits":
			{
				for (TheatreOfBloodStatsInfoBox box : infoBoxes.values())
				{
					box.rebuildTooltip();
				}
				break;
			}
		}
	}

	@Subscribe
	public void onWorldViewLoaded(WorldViewLoaded event)
	{
		int[] regions = event.getWorldView().getMapRegions();

		boolean isTobRegion = false;
		for (int[] tobRegion : TOB_REGION_IDS)
		{
			if (Arrays.equals(tobRegion, regions))
			{
				isTobRegion = true;
				break;
			}
		}

		if (!isTobRegion)
		{
			if (!infoBoxes.isEmpty())
			{
				resetAllInfoBoxes();
			}
			return;
		}

		if (Arrays.equals(TOB_LOBBY_REGION_IDS, regions) || Arrays.equals(THRONE_ROOM_REGION_IDS, regions))
		{
			resetAll();
			return;
		}

		for (RoomTracker tracker : allTrackers)
		{
			if (Arrays.equals(tracker.getRegionIds(), regions) && tracker != roomTracker)
			{
				tracker.reset();
				roomTracker = tracker;
				return;
			}
		}
	}

