package com.runetrivia.util;

/**
 * OSRS display-name helpers. Mirrors {@code server/src/names.ts}.
 *
 * The server uses normalized form (lowercase, NBSP-to-space, trim) as the
 * lookup key. Some wire messages (QUESTION_RESOLVED.results, scores) are
 * keyed by normalized name; others (MATCH_STARTED.opponents, ARENA_STAGED.tiles)
 * use display name. To resolve correctly we normalize on the way in.
 */
public final class NameUtil
{
    /** Non-breaking space (U+00A0) — the OSRS client uses this in place of a regular space in some paths. */
    private static final char NBSP = ' ';

    private NameUtil()
    {
    }

    /**
     * Normalize an OSRS display name into the server's lookup key:
     * NBSP is replaced with a regular space, then trim + lowercase.
     */
    public static String normalize(String displayName)
    {
        if (displayName == null) return "";
        return displayName.replace(NBSP, ' ').trim().toLowerCase();
    }
}

package com.runetrivia.match;

import com.runetrivia.net.messages.Domain;
import javax.inject.Inject;
import javax.inject.Singleton;
import lombok.extern.slf4j.Slf4j;
import net.runelite.api.Animation;
import net.runelite.api.Client;
import net.runelite.api.Model;
import net.runelite.api.ModelData;
import net.runelite.api.NPCComposition;
import net.runelite.api.Player;
import net.runelite.api.RuneLiteObject;
import net.runelite.api.coords.LocalPoint;
import net.runelite.api.coords.WorldPoint;
import net.runelite.client.callback.ClientThread;

/**
 * Spawns the trivia host as a {@link RuneLiteObject} with the real OSRS
 * NPC model, applies the NPC's recolors, and positions it at the assigned
 * tile.
 *
 * <h3>Model-loading dance</h3>
 *
 * {@link Client#loadModelData(int)} returns null when the model file is not
 * yet in the cache (RuneLite loads assets lazily). We therefore can't
 * guarantee a successful spawn on the first attempt. The renderer retains
 * the "want to spawn" intent in {@link #pendingNpcId} / {@link #pendingTile}
 * and {@link #onTick()} re-attempts every GameTick until all parts have
 * loaded.
 *
 * <h3>Threading</h3>
 *
 * Everything that touches the {@link Client} API runs on the game thread.
 * Public methods marshal through {@link ClientThread#invoke}. Internal
 * methods assume they're already on the right thread.
 */
@Singleton
@Slf4j
public class HostNpcRenderer
{
    /** Default idle animation: generic human standing pose. Override per-NPC if it looks wrong. */
    public static final int DEFAULT_IDLE_ANIM = 808;
    /** Standard human walk animation. Suitable for most humanoid NPC skeletons. */
    public static final int DEFAULT_WALK_ANIM = 819;
    /** South-facing — used only until {@link #updateOrientation()} starts tracking the player. */
    private static final int INITIAL_ORIENTATION = 0;
    /** Per-tick orientation step (JagEx units). 256 = ~45° per tick → ~4 ticks for a 180° turn. */
    private static final int ORIENTATION_STEP = 256;

    private final Client client;
    private final ClientThread clientThread;

    // -- Intent (touched only on the client thread) -----------------------
    private int pendingNpcId = -1;
    private Domain.WorldPoint pendingTile;
    private RuneLiteObject obj;
    private boolean spawned;

    // -- Animation state --------------------------------------------------
    private int idleAnimId = DEFAULT_IDLE_ANIM;
    /** Wall-clock ms when the current one-shot reaction should revert to idle. 0 = no active reaction. */
    private long reactionEndsAt = 0;
    /** Whether the looping idle animation is currently applied. Falsey -> retry next tick. */
    private boolean idleApplied = false;
    /** Current rendered orientation, smoothed via ORIENTATION_STEP per tick. */
    private int currentOrient = INITIAL_ORIENTATION;

    // -- Walk state -------------------------------------------------------
    /**
     * Walking is modelled the same way OSRS does it: each segment is one
     * tile that takes one game tick (~600ms) to traverse. The model
     * interpolates linearly *within* a segment, then snaps to the segment
     * end on the next GameTick and re-targets the following tile. This is
     * what keeps the leg-step animation locked to the body's motion —
     * without segment-paced movement the model gait-cycles independently
     * of position and the eye reads it as gliding/ice-skating.
     */
    /** Approx OSRS game-tick duration; matches the cadence of the GameTick event. */
    private static final long TICK_MS = 600;
    private boolean walking = false;
    /** Final destination tile (snapshot of caller intent). */
    private Domain.WorldPoint walkEndTile;
    /** Current segment endpoints (one tile apart). Null when not walking. */
    private Domain.WorldPoint walkSegmentStart;
    private Domain.WorldPoint walkSegmentEnd;
    /** Wall-clock start of the current segment. Resets on each GameTick advance. */
    private long walkSegmentStartedAt;
    /** Animation used during the walk. Per-NPC override possible later. */
    private int walkAnimId = DEFAULT_WALK_ANIM;
    /** Optional callback run on the client thread once the host arrives at walkEndTile. */
    private Runnable walkCompletionCallback;
    /**
     * A walk that has been requested but hasn't started yet — waiting for
     * the next GameTick to align segment timing with the game's tick clock.
     * Without this alignment, segments and GameTicks drift independently
     * and the host either skips forward (segment commits early) or stutters
     * (segment finishes early and waits).
     */
    private Domain.WorldPoint pendingWalkTarget;
    private Runnable pendingWalkCallback;

    /**
     * Callbacks queued via {@link #whenArrived(Runnable)} — run in FIFO order
     * once the host finishes its current/pending walk. Used by the plugin to
     * defer host speech that the server might emit before the walk-in
     * finishes (e.g. MATCH_STARTED's "get ready" line, which arrives ~1s
     * into a ~3s walk-in).
     */
    private final java.util.ArrayDeque<Runnable> arrivalCallbacks = new java.util.ArrayDeque<>();

    @Inject
    public HostNpcRenderer(Client client, ClientThread clientThread)
    {
        this.client = client;
        this.clientThread = clientThread;
    }

    /**
     * Ask the renderer to spawn the given NPC at the given tile. Idempotent —
     * calling with the same args while already spawned is a no-op; calling
     * with different args despawns the current object first.
     */
    public void requestSpawn(int npcId, Domain.WorldPoint tile)
    {
        if (npcId <= 0 || tile == null) return;
        clientThread.invoke(() ->
        {
            if (spawned && npcId == pendingNpcId && tile.equals(pendingTile))
            {
                return;
            }
            despawnInternal();
            pendingNpcId = npcId;
            pendingTile = tile;
            spawned = false;
            trySpawn();
        });
    }

    /** Despawn whatever's currently shown. Idempotent. */
    public void requestDespawn()
    {
        clientThread.invoke(() ->
        {
            despawnInternal();
            pendingNpcId = -1;
            pendingTile = null;
        });
    }

    /**
     * Override the looping idle animation. Defaults to {@link #DEFAULT_IDLE_ANIM}
     * (generic human standing). Useful for non-humanoid NPCs whose default
     * skeleton doesn't match the human bind pose.
     */
    public void setIdleAnimation(int animId)
    {
        clientThread.invoke(() ->
        {
            this.idleAnimId = animId;
            if (spawned && reactionEndsAt == 0)
            {
                applyAnimation(animId, true);
            }
        });
    }

    /**
     * Walk from the current position to {@code target}, one tile per game
     * tick. The total walk duration is implicitly {@code chebyshev(start,
     * target) * TICK_MS}. The {@code durationMs} parameter is retained for
     * caller compatibility but ignored — OSRS movement is tile-paced, not
     * duration-paced, and forcing a different speed is what made the walk
     * look like ice-skating.
     *
     * While walking:
     *   * the walk animation plays (looping);
     *   * each GameTick (~600ms) the segment advances by one tile;
     *   * within each segment, position is linearly interpolated per
     *     ClientTick so the model glides smoothly between tile centers
     *     in sync with the step animation;
     *   * on arrival, position snaps to the destination tile and the host
     *     reverts to idle.
     */
    public void walkTo(Domain.WorldPoint target, long durationMs)
    {
        walkTo(target, (Runnable) null);
    }

    /**
     * Same as {@link #walkTo(Domain.WorldPoint, long)} but with a callback
     * fired on the client thread the moment the host arrives at the
     * destination. Cleaner than scheduling separate Timers that race the
     * walk's actual completion.
     */
    public void walkTo(Domain.WorldPoint target, Runnable onArrived)
    {
        if (target == null) return;
        clientThread.invoke(() ->
        {
            if (!spawned || obj == null) return;
            // Queue the walk to start on the next GameTick. Starting at an
            // arbitrary wall-clock time would make segments drift relative
            // to the GameTick clock, which is how the moonwalk / stutter
            // bugs we hit earlier manifested. The cost is up to ~600ms
            // delay before walking visibly starts — same delay OSRS itself
            // has between click-to-move and the first step.
            pendingWalkTarget = target;
            pendingWalkCallback = onArrived;
        });
    }

    /**
     * Run {@code r} on the client thread once the host has finished any
     * in-progress or pending walk. Fires immediately if no walk is active.
     * Multiple callbacks run in FIFO order.
     *
     * Used to keep host speech (e.g. the "get ready" line emitted by the
     * server's MATCH_STARTED frame) from appearing while the host is still
     * mid-stride during the walk-in.
     */
    public void whenArrived(Runnable r)
    {
        if (r == null) return;
        clientThread.invoke(() ->
        {
            if (!walking && pendingWalkTarget == null)
            {
                r.run();
                return;
            }
            arrivalCallbacks.add(r);
        });
    }

    /** Drain queued arrival callbacks. Caller must already be on client thread. */
    private void fireArrivalCallbacks()
    {
        while (!arrivalCallbacks.isEmpty())
        {
            Runnable r = arrivalCallbacks.poll();
            try { r.run(); }
            catch (Exception e) { log.warn("arrival callback threw: {}", e.toString()); }
        }
    }

    /** One-tile step from {@code from} toward {@code to}. Returns null if already there. */
    private static Domain.WorldPoint nextTileToward(Domain.WorldPoint from, Domain.WorldPoint to)
    {
        if (from == null || to == null) return null;
        int dx = Integer.signum(to.x - from.x);
        int dy = Integer.signum(to.y - from.y);
        if (dx == 0 && dy == 0) return null;
        return new Domain.WorldPoint(from.x + dx, from.y + dy, from.plane);
    }

    /** Override the walk animation. Defaults to {@link #DEFAULT_WALK_ANIM}. */
    public void setWalkAnimation(int animId)
    {
        clientThread.invoke(() -> this.walkAnimId = animId);
    }

    /**
     * Per-client-tick callback (~20ms). Used for smooth position interpolation
     * during walks — much finer-grained than the 600ms GameTick. Called from
     * the plugin's ClientTick subscriber.
     */
    public void onClientTick()
    {
        if (!spawned || obj == null || !walking) return;
        if (walkSegmentStart == null || walkSegmentEnd == null) return;

        // Linear interpolation across the current segment. Linear (not cosine
        // ease) matches how the real game animates a unit between tile
        // centers within a tick — a constant-velocity step in sync with the
        // gait animation. Easing would re-introduce the moonwalk feel.
        long elapsed = System.currentTimeMillis() - walkSegmentStartedAt;
        double t = Math.min(1.0, elapsed / (double) TICK_MS);

        WorldPoint startWorld = new WorldPoint(walkSegmentStart.x, walkSegmentStart.y, walkSegmentStart.plane);
        WorldPoint endWorld = new WorldPoint(walkSegmentEnd.x, walkSegmentEnd.y, walkSegmentEnd.plane);
        LocalPoint startLp = LocalPoint.fromWorld(client, startWorld);
        LocalPoint endLp = LocalPoint.fromWorld(client, endWorld);
        if (startLp == null || endLp == null) return;
        int lx = (int) Math.round(startLp.getX() + (endLp.getX() - startLp.getX()) * t);
        int ly = (int) Math.round(startLp.getY() + (endLp.getY() - startLp.getY()) * t);
        obj.setLocation(new LocalPoint(lx, ly), walkSegmentEnd.plane);

        // Face the direction of travel — keep the orientation snapped to
        // the segment's direction so the model faces forward as it walks.
        int dx = walkSegmentEnd.x - walkSegmentStart.x;
        int dy = walkSegmentEnd.y - walkSegmentStart.y;
        if (dx != 0 || dy != 0)
        {
            int target = ((int) (Math.atan2(-dx, -dy) * 1024 / Math.PI)) & 0x7FF;
            currentOrient = target;
            obj.setOrientation(currentOrient);
        }
    }

    /**
     * Play a reaction animation for the given duration, then revert to idle.
     *
     * Implementation detail: we set the reaction to loop (shouldLoop=true)
     * for the entire duration. {@code RuneLiteObject} stops rendering its
     * model the moment a non-looping animation completes — which would
     * make the host disappear mid-reaction. Looping the reaction keeps the
     * model visible; the timer-based revert swaps back to idle when the
     * duration elapses.
     */
    public void playReaction(int animId, long durationMs)
    {
        clientThread.invoke(() ->
        {
            if (!spawned) return;
            if (!applyAnimation(animId, true)) return;
            reactionEndsAt = System.currentTimeMillis() + Math.max(0, durationMs);
        });
    }

    /**
     * Called from the plugin's GameTick handler. Handles:
     *   * retrying the spawn until model parts have loaded;
     *   * reverting one-shot reactions back to idle when their duration elapses;
     *   * smoothly rotating to face the local player.
     */
    public void onTick()
    {
        if (!spawned)
        {
            if (pendingNpcId > 0 && pendingTile != null) trySpawn();
            return;
        }

        // Start a queued walk now (at this GameTick boundary). All segments
        // begin and end on GameTicks so interpolation completes cleanly
        // each tick.
        if (pendingWalkTarget != null && !walking)
        {
            startPendingWalk();
            // Return immediately — the first segment was just initialized
            // with walkSegmentStartedAt=now. Falling through to
            // advanceWalkSegment in the same tick would commit and discard
            // segment 1 before any ClientTick gets to render it, producing
            // a one-tile teleport on the first step. The first segment
            // gets its full TICK_MS only if we wait for the *next* GameTick
            // to advance.
            if (walking) return;
        }

        if (walking)
        {
            advanceWalkSegment();
            return;
        }

        // Reaction expired -> back to idle loop.
        if (reactionEndsAt > 0 && System.currentTimeMillis() >= reactionEndsAt)
        {
            reactionEndsAt = 0;
            idleApplied = false; // force reapply below
        }
        // If we're not mid-reaction and the idle isn't currently applied
        // (typically because the animation cache was cold at spawn time),
        // keep retrying every tick until it sticks.
        if (reactionEndsAt == 0 && !idleApplied)
        {
            idleApplied = applyAnimation(idleAnimId, true);
        }
        updateOrientation();
    }

    /**
     * Activate a pending walk. Called from {@link #onTick} so segment timing
     * is anchored to GameTicks. Switches to the walk animation and sets up
     * the first one-tile segment, which will complete by the next GameTick.
     */
    private void startPendingWalk()
    {
        walkEndTile = pendingWalkTarget;
        walkCompletionCallback = pendingWalkCallback;
        pendingWalkTarget = null;
        pendingWalkCallback = null;

        walkSegmentStart = pendingTile;
        walkSegmentEnd = nextTileToward(pendingTile, walkEndTile);
        walkSegmentStartedAt = System.currentTimeMillis();
        walking = walkSegmentEnd != null;

        if (walking)
        {
            applyAnimation(walkAnimId, true);
            idleApplied = false;
            reactionEndsAt = 0;
        }
        else
        {
            // Already at the target — fire callback immediately.
            if (walkCompletionCallback != null)
            {
                Runnable cb = walkCompletionCallback;
                walkCompletionCallback = null;
                cb.run();
            }
            // Any whenArrived() queue also drains here, since we never had
            // a walk to wait for in the first place.
            fireArrivalCallbacks();
        }
    }

    /**
     * One-tile step per GameTick. Because every segment begins at a
     * GameTick (see {@link #startPendingWalk}) and GameTicks fire every
     * ~TICK_MS, the interpolation in {@link #onClientTick} naturally
     * reaches t=1.0 by the time we get here — no need to gate on elapsed.
     */
    private void advanceWalkSegment()
    {
        if (walkSegmentEnd == null) return;

        pendingTile = walkSegmentEnd;
        // Reached the final destination?
        if (walkSegmentEnd.x == walkEndTile.x && walkSegmentEnd.y == walkEndTile.y)
        {
            WorldPoint world = new WorldPoint(walkEndTile.x, walkEndTile.y, walkEndTile.plane);
            LocalPoint lp = LocalPoint.fromWorld(client, world);
            if (lp != null) obj.setLocation(lp, walkEndTile.plane);
            walking = false;
            walkSegmentStart = null;
            walkSegmentEnd = null;
            idleApplied = applyAnimation(idleAnimId, true);
            // Fire arrival callback on the client thread.
            Runnable cb = walkCompletionCallback;
            walkCompletionCallback = null;
            if (cb != null) cb.run();
            // Drain any whenArrived() queue — deferred speech etc.
            fireArrivalCallbacks();
            return;
        }
        // Set up the next one-tile segment.
        walkSegmentStart = walkSegmentEnd;
        walkSegmentEnd = nextTileToward(walkSegmentStart, walkEndTile);
        walkSegmentStartedAt = System.currentTimeMillis();
    }

    // -- internal ---------------------------------------------------------

    private void trySpawn()
    {
        if (pendingNpcId <= 0 || pendingTile == null) return;

        NPCComposition comp = client.getNpcDefinition(pendingNpcId);
        if (comp == null)
        {
            // Composition may itself be lazy-loaded; try again next tick.
            return;
        }
        int[] modelIds = comp.getModels();
        if (modelIds == null || modelIds.length == 0)
        {
            log.warn("NPC {} has no models", pendingNpcId);
            cancel();
            return;
        }

        ModelData[] parts = new ModelData[modelIds.length];
        for (int i = 0; i < modelIds.length; i++)
        {
            parts[i] = client.loadModelData(modelIds[i]);
            if (parts[i] == null)
            {
                // At least one part not cached yet — retry next tick.
                return;
            }
        }

        ModelData merged = parts.length == 1 ? parts[0] : client.mergeModels(parts);
        if (merged == null)
        {
            log.warn("mergeModels returned null for npc {}", pendingNpcId);
            cancel();
            return;
        }

        // Apply NPC recolors (so e.g. King Roald isn't wearing the base palette).
        short[] origColors = comp.getColorToReplace();
        short[] newColors = comp.getColorToReplaceWith();
        if (origColors != null && newColors != null && origColors.length > 0)
        {
            merged.cloneColors();
            int n = Math.min(origColors.length, newColors.length);
            for (int i = 0; i < n; i++)
            {
                merged.recolor(origColors[i], newColors[i]);
            }
        }

        Model model;
        try
        {
            model = merged.light();
        }
        catch (Exception e)
        {
            log.warn("lighting model failed for npc {}: {}", pendingNpcId, e.toString());
            cancel();
            return;
        }
        if (model == null)
        {
            log.warn("light() returned null for npc {}", pendingNpcId);
            cancel();
            return;
        }

        WorldPoint world = new WorldPoint(pendingTile.x, pendingTile.y, pendingTile.plane);
        LocalPoint lp = LocalPoint.fromWorld(client, world);
        if (lp == null)
        {
            // Tile outside the loaded scene — try again next tick (player may
            // still be walking into the region).
            return;
        }

        RuneLiteObject newObj = client.createRuneLiteObject();
        newObj.setModel(model);
        this.currentOrient = INITIAL_ORIENTATION;
        newObj.setOrientation(currentOrient);
        newObj.setLocation(lp, pendingTile.plane);
        newObj.setActive(true);

        this.obj = newObj;
        this.spawned = true;
        // Kick off the idle loop immediately so the NPC isn't frozen in the
        // bind pose. If the animation is cold-cached this returns false;
        // onTick keeps retrying every tick until it succeeds.
        this.idleApplied = applyAnimation(idleAnimId, true);
        log.info("spawned host NPC id={} ({}) at ({}, {}, plane {}); idleApplied={}",
            pendingNpcId, comp.getName(), pendingTile.x, pendingTile.y, pendingTile.plane, idleApplied);
    }

    /**
     * Set the RuneLiteObject's current animation to the given id, looping
     * or one-shot. Returns true if applied, false if the animation wasn't
     * available (cache miss — caller may want to retry later).
     */
    private boolean applyAnimation(int animId, boolean loop)
    {
        if (obj == null || animId <= 0) return false;
        Animation anim = client.loadAnimation(animId);
        if (anim == null) return false;
        obj.setAnimation(anim);
        obj.setShouldLoop(loop);
        return true;
    }

    /**
     * Smoothly rotate the host to face the local player. JagEx orientation
     * units are 0..2047, where 0=south, 512=west, 1024=north, 1536=east.
     *
     * The formula {@code atan2(-dx, -dy)} maps the world-space delta from
     * NPC to player into that convention; we then advance currentOrient
     * toward the target by at most ORIENTATION_STEP per tick (so the
     * NPC doesn't snap-rotate jarringly).
     */
    private void updateOrientation()
    {
        if (obj == null || pendingTile == null) return;
        Player me = client.getLocalPlayer();
        if (me == null) return;
        WorldPoint myWp = me.getWorldLocation();
        if (myWp == null) return;
        if (myWp.getPlane() != pendingTile.plane) return;
        int dx = myWp.getX() - pendingTile.x;
        int dy = myWp.getY() - pendingTile.y;
        if (dx == 0 && dy == 0) return; // player on the host tile — keep facing where we were

        int target = ((int) (Math.atan2(-dx, -dy) * 1024 / Math.PI)) & 0x7FF;
        int diff = ((target - currentOrient + 1024 + 2048) % 2048) - 1024;
        if (Math.abs(diff) <= ORIENTATION_STEP)
        {
            currentOrient = target;
        }
        else
        {
            currentOrient = ((currentOrient + (diff > 0 ? ORIENTATION_STEP : -ORIENTATION_STEP)) + 2048) % 2048;
        }
        obj.setOrientation(currentOrient);
    }

    private void despawnInternal()
    {
        if (obj != null)
        {
            try
            {
                obj.setActive(false);
            }
            catch (Exception e)
            {
                log.warn("despawn setActive(false) threw: {}", e.toString());
            }
            obj = null;
        }
        spawned = false;
        reactionEndsAt = 0;
        idleApplied = false;
        currentOrient = INITIAL_ORIENTATION;
        walking = false;
        walkSegmentStart = null;
        walkSegmentEnd = null;
        walkEndTile = null;
        walkCompletionCallback = null;
        pendingWalkTarget = null;
        pendingWalkCallback = null;
        arrivalCallbacks.clear();
    }

    /** Permanent failure: drop the request so we stop retrying every tick. */
    private void cancel()
    {
        pendingNpcId = -1;
        pendingTile = null;
        despawnInternal();
    }
}

package com.runetrivia.match;

import com.runetrivia.net.messages.Domain;
import com.runetrivia.net.messages.Domain.ArenaProposal;
import com.runetrivia.net.messages.Domain.WorldPoint;
import javax.inject.Inject;
import javax.inject.Singleton;
import net.runelite.api.Client;
import net.runelite.api.CollisionData;
import net.runelite.api.CollisionDataFlag;
import net.runelite.api.Player;
import net.runelite.api.coords.LocalPoint;

/**
 * Walks outward from the local player looking for a tile that can host the
 * trivia NPC, with two walkable neighbors on opposite sides for the two
 * players. Returns null if no suitable arrangement fits within {@link #MAX_RADIUS}.
 *
 * Everything here runs on the game thread (or with a snapshot of the scene
 * captured on it). The Client is touched only via methods documented as
 * safe outside the game thread (scene + collision data are guarded by
 * RuneLite's API for read-only access).
 */
@Singleton
public class ArenaTileFinder
{
    /** Search no more than this many tiles out (Chebyshev distance). */
    public static final int MAX_RADIUS = 5;

    private static final int BLOCK_FLAGS = CollisionDataFlag.BLOCK_MOVEMENT_FULL
        | CollisionDataFlag.BLOCK_MOVEMENT_OBJECT;

    private final Client client;

    @Inject
    public ArenaTileFinder(Client client)
    {
        this.client = client;
    }

    /**
     * Find a usable arena around the local player. Returns null if the
     * player isn't loaded or no suitable tile arrangement exists nearby.
     */
    public ArenaProposal findArena()
    {
        Player me = client.getLocalPlayer();
        if (me == null)
        {
            return null;
        }
        net.runelite.api.coords.WorldPoint anchorWp = me.getWorldLocation();
        if (anchorWp == null)
        {
            return null;
        }
        LocalPoint anchorLp = LocalPoint.fromWorld(client, anchorWp);
        if (anchorLp == null)
        {
            return null;
        }

        int plane = client.getPlane();
        CollisionData[] maps = client.getCollisionMaps();
        if (maps == null || maps.length <= plane || maps[plane] == null)
        {
            return null;
        }
        int[][] flags = maps[plane].getFlags();

        int sx = anchorLp.getSceneX();
        int sy = anchorLp.getSceneY();

        // Spiral outward at radius r (Chebyshev). Order: closer first.
        for (int r = 1; r <= MAX_RADIUS; r++)
        {
            for (int dx = -r; dx <= r; dx++)
            {
                for (int dy = -r; dy <= r; dy++)
                {
                    if (Math.max(Math.abs(dx), Math.abs(dy)) != r)
                    {
                        continue; // only the ring at distance r
                    }
                    int tx = sx + dx;
                    int ty = sy + dy;
                    if (!inBounds(flags, tx, ty) || !walkable(flags, tx, ty))
                    {
                        continue;
                    }
                    Pair pair = findOppositeNeighbors(flags, tx, ty);
                    if (pair == null)
                    {
                        continue;
                    }
                    return buildProposal(plane, tx, ty, pair, anchorWp);
                }
            }
        }
        return null;
    }

    private boolean walkable(int[][] flags, int sx, int sy)
    {
        return (flags[sx][sy] & BLOCK_FLAGS) == 0;
    }

    private boolean inBounds(int[][] flags, int sx, int sy)
    {
        return sx >= 0 && sy >= 0 && sx < flags.length && flags[sx].length > sy;
    }

    private Pair findOppositeNeighbors(int[][] flags, int sx, int sy)
    {
        // East+West preferred, then North+South.
        if (inBounds(flags, sx - 1, sy) && inBounds(flags, sx + 1, sy)
            && walkable(flags, sx - 1, sy) && walkable(flags, sx + 1, sy))
        {
            return new Pair(-1, 0, 1, 0);
        }
        if (inBounds(flags, sx, sy - 1) && inBounds(flags, sx, sy + 1)
            && walkable(flags, sx, sy - 1) && walkable(flags, sx, sy + 1))
        {
            return new Pair(0, -1, 0, 1);
        }
        return null;
    }

    private ArenaProposal buildProposal(int plane, int sx, int sy, Pair p, net.runelite.api.coords.WorldPoint anchorWp)
    {
        int baseX = anchorWp.getX() - (LocalPoint.fromWorld(client, anchorWp)).getSceneX();
        int baseY = anchorWp.getY() - (LocalPoint.fromWorld(client, anchorWp)).getSceneY();

        WorldPoint npcTile = new WorldPoint(baseX + sx, baseY + sy, plane);
        WorldPoint challengerTile = new WorldPoint(baseX + sx + p.dxA, baseY + sy + p.dyA, plane);
        WorldPoint challengedTile = new WorldPoint(baseX + sx + p.dxB, baseY + sy + p.dyB, plane);

        ArenaProposal arena = new ArenaProposal();
        arena.regionId = anchorWp.getRegionID();
        arena.npcTile = npcTile;
        arena.challengerTile = challengerTile;
        arena.challengedTile = challengedTile;
        return arena;
    }

    /** WorldPoint wrapper for the challenger's current location, for inclusion in the wire payload. */
    public WorldPoint currentLocation()
    {
        Player me = client.getLocalPlayer();
        if (me == null || me.getWorldLocation() == null)
        {
            return null;
        }
        net.runelite.api.coords.WorldPoint wp = me.getWorldLocation();
        return new WorldPoint(wp.getX(), wp.getY(), wp.getPlane());
    }

    private static final class Pair
    {
        final int dxA;
        final int dyA;
        final int dxB;
        final int dyB;

        Pair(int dxA, int dyA, int dxB, int dyB)
        {
            this.dxA = dxA;
            this.dyA = dyA;
            this.dxB = dxB;
            this.dyB = dyB;
        }
    }
}

package com.runetrivia.match;

import com.google.gson.Gson;
import com.google.gson.JsonElement;
import com.google.gson.JsonObject;
import java.io.IOException;
import java.io.InputStream;
import java.io.InputStreamReader;
import java.nio.charset.StandardCharsets;
import java.util.ArrayList;
import java.util.Collections;
import java.util.HashMap;
import java.util.List;
import java.util.Map;
import java.util.concurrent.ThreadLocalRandom;
import javax.inject.Inject;
import javax.inject.Singleton;
import lombok.extern.slf4j.Slf4j;

/**
 * Loads per-NPC dialogue lines from classpath resources under
 * {@code /host_lines/}. See {@code host_lines/README.md} for the schema.
 *
 * Override files are partial — any missing category falls back to
 * {@code _default.json}. Per-NPC files are loaded lazily on first lookup
 * and cached for the lifetime of the plugin process.
 */
@Singleton
@Slf4j
public class HostLines
{
    private static final String RESOURCE_ROOT = "/host_lines/";
    private static final String DEFAULTS_FILE = "_default.json";

    /** category -> lines, populated from _default.json on construction. */
    private final Map<String, List<String>> defaults = new HashMap<>();
    /** slug -> category -> lines. Populated lazily on first lookup per slug. */
    private final Map<String, Map<String, List<String>>> overrides = new HashMap<>();
    /** Scalar int fields from _default.json (e.g. "idleAnimation"). */
    private final Map<String, Integer> defaultInts = new HashMap<>();
    /** slug -> int fields. Lazily loaded same as line overrides. */
    private final Map<String, Map<String, Integer>> overrideInts = new HashMap<>();
    /** Slugs that we've already attempted to load (success or miss) — never retry. */
    private final Map<String, Boolean> attempted = new HashMap<>();

    private final Gson gson;

    @Inject
    public HostLines(Gson gson)
    {
        this.gson = gson;
        loadDefaults();
    }

    /**
     * Convert a display name into the slug used for the JSON filename:
     * lowercase + any non-[a-z0-9] run replaced with a single '_'.
     * E.g. "King Roald" -> "king_roald".
     */
    public static String slugFor(String displayName)
    {
        if (displayName == null) return "_default";
        String s = displayName.toLowerCase().replaceAll("[^a-z0-9]+", "_");
        // Trim leading/trailing underscores that the replace may have introduced.
        return s.replaceAll("^_+|_+$", "");
    }

    /**
     * Pick a random line from the given category for the given host, applying
     * {placeholder} substitutions. Returns null if the category has no lines
     * (which shouldn't happen if _default.json is intact, but defends against
     * editing accidents).
     */
    public String pick(String displayName, String category, Map<String, String> interpolations)
    {
        List<String> lines = linesFor(displayName, category);
        if (lines == null || lines.isEmpty()) return null;
        String chosen = lines.get(ThreadLocalRandom.current().nextInt(lines.size()));
        return interpolate(chosen, interpolations);
    }

    private List<String> linesFor(String displayName, String category)
    {
        String slug = slugFor(displayName);
        Map<String, List<String>> over = loadOverride(slug);
        if (over != null)
        {
            List<String> custom = over.get(category);
            if (custom != null && !custom.isEmpty()) return custom;
        }
        return defaults.get(category);
    }

    /**
     * Look up a scalar integer config value for the given host. Per-NPC
     * overrides win; falls back to the value in {@code _default.json} if
     * present; otherwise returns {@code fallback}.
     *
     * Used for things like {@code idleAnimation} where each NPC may want
     * a different value (Reldo reads a book, King Roald sits, etc.).
     */
    public int getInt(String displayName, String key, int fallback)
    {
        String slug = slugFor(displayName);
        // Trigger a load of the override file so overrideInts is populated.
        loadOverride(slug);
        Map<String, Integer> over = overrideInts.get(slug);
        if (over != null && over.containsKey(key)) return over.get(key);
        Integer def = defaultInts.get(key);
        return def != null ? def : fallback;
    }

    private Map<String, List<String>> loadOverride(String slug)
    {
        Map<String, List<String>> cached = overrides.get(slug);
        if (cached != null) return cached;
        if (attempted.containsKey(slug)) return null;
        attempted.put(slug, true);
        Map<String, Integer> intsOut = new HashMap<>();
        Map<String, List<String>> loaded = loadJson(slug + ".json", intsOut);
        if (loaded != null) overrides.put(slug, loaded);
        if (!intsOut.isEmpty()) overrideInts.put(slug, intsOut);
        return loaded;
    }

    private void loadDefaults()
    {
        Map<String, List<String>> def = loadJson(DEFAULTS_FILE, defaultInts);
        if (def == null)
        {
            log.warn("host_lines/_default.json missing — bubble will be silent for unhandled categories");
            return;
        }
        defaults.putAll(def);
    }

    /**
     * Parse a host-config JSON file. Categories whose value is an array of
     * strings are treated as line categories (returned via the return value).
     * Categories whose value is a number are written into {@code intsOut}
     * (for things like {@code "idleAnimation": 847}). Other shapes — strings,
     * objects, the {@code _doc} comment — are ignored.
     *
     * Returns null if the file is not on the classpath.
     */
    private Map<String, List<String>> loadJson(String filename, Map<String, Integer> intsOut)
    {
        String path = RESOURCE_ROOT + filename;
        try (InputStream is = HostLines.class.getResourceAsStream(path))
        {
            if (is == null) return null;
            JsonObject root = gson.fromJson(new InputStreamReader(is, StandardCharsets.UTF_8), JsonObject.class);
            if (root == null) return Collections.emptyMap();
            Map<String, List<String>> out = new HashMap<>();
            for (Map.Entry<String, JsonElement> entry : root.entrySet())
            {
                JsonElement v = entry.getValue();
                if (v == null) continue;
                if (v.isJsonArray())
                {
                    List<String> lines = new ArrayList<>();
                    v.getAsJsonArray().forEach(el ->
                    {
                        if (el != null && el.isJsonPrimitive()) lines.add(el.getAsString());
                    });
                    if (!lines.isEmpty()) out.put(entry.getKey(), lines);
                }
                else if (v.isJsonPrimitive() && v.getAsJsonPrimitive().isNumber())
                {
                    try { intsOut.put(entry.getKey(), v.getAsInt()); }
                    catch (NumberFormatException ignored) { /* malformed number */ }
                }
            }
            return out;
        }
        catch (IOException e)
        {
            log.warn("failed reading {}: {}", path, e.toString());
            return null;
        }
        catch (Exception e)
        {
            log.warn("failed parsing {}: {}", path, e.toString());
            return null;
        }
    }

    /** Replace {key} tokens with values from the map. Unknown tokens are left as-is. */
    static String interpolate(String template, Map<String, String> values)
    {
        if (values == null || values.isEmpty()) return template;
        String out = template;
        for (Map.Entry<String, String> e : values.entrySet())
        {
            String token = "{" + e.getKey() + "}";
            // String.replace handles overlapping correctly and is fine for our scale.
            out = out.replace(token, e.getValue() == null ? "" : e.getValue());
        }
        return out;
    }
}

package com.runetrivia.match;

import com.runetrivia.net.messages.Domain.HostNpc;
import com.runetrivia.net.messages.Domain.PerPlayerQuestionResult;
import com.runetrivia.net.messages.Domain.WorldPoint;
import com.runetrivia.util.NameUtil;
import java.util.HashMap;
import java.util.Map;

/**
 * Local plugin-side view of an active match. Owned by the plugin core;
 * mutated only from the game/client thread. Read-only snapshots can be
 * passed to UI components.
 *
 * Lifecycle:
 *   ARENA_STAGED          -> new MatchSession(STAGING)
 *   PLAYER_READY (local)  -> session.localReady = true
 *   MATCH_STARTED         -> state = IN_PROGRESS, scores populated
 *   QUESTION_DELIVERED    -> setCurrentQuestion(...)
 *   QUESTION_RESOLVED     -> applyResolution(...)
 *   MATCH_COMPLETED       -> state = COMPLETE
 *   (or MATCH_FORFEIT/CHALLENGE_RESOLVED if cancelled)
 */
public final class MatchSession
{
    public enum State { STAGING, IN_PROGRESS, COMPLETE }

    /**
     * Chebyshev distance from the host tile that defines the "ready" arena.
     * 2 tiles = 5x5 area (25 tiles), generous enough that pathing into the
     * radius is forgiving without making the arena feel huge.
     */
    public static final int ARENA_RADIUS = 2;

    /** Match id from the server. */
    public final String matchId;
    /** The OSRS region that bounds this match. */
    public final int regionId;
    /** Host NPC the server picked. */
    public final HostNpc host;
    /** Local player's display name (as known by the server). */
    public final String myDisplayName;
    /** Opponent's display name. */
    public final String opponentDisplayName;
    /** Normalized form of {@link #myDisplayName} (matches server keys). */
    public final String myNormalized;
    /** Normalized form of {@link #opponentDisplayName}. */
    public final String opponentNormalized;
    /** Tile we should stand on during staging. */
    public final WorldPoint myAssignedTile;
    /** Tile opponent should stand on. */
    public final WorldPoint opponentAssignedTile;
    /** Original staging deadline (epoch ms). */
    public final long stagingDeadline;

    private State state;
    private boolean localReady;
    /** Running scores keyed by display name. Populated by MATCH_STARTED. */
    private final Map<String, Integer> scores = new HashMap<>();

    /** Number of consecutive ticks the local player's region has differed from the arena region. */
    private int outOfRegionTicks = 0;
    private int currentQuestionIndex = -1;
    private String currentPrompt;
    private long currentDeadline;
    /**
     * Becomes true between QUESTION_RESOLVED for question N and
     * QUESTION_DELIVERED for question N+1 (or MATCH_COMPLETED).
     * While true, chat input is not forwarded as an answer.
     */
    private boolean questionResolved = true;
    /** Display name of whoever got the most recent question right (null = nobody). */
    private String lastCorrectDisplay;
    /** Canonical answer of the most recent question (for UI/overhead). */
    private String lastCanonicalAnswer;

    private MatchSession(
        String matchId,
        int regionId,
        HostNpc host,
        String myDisplayName,
        String opponentDisplayName,
        WorldPoint myAssignedTile,
        WorldPoint opponentAssignedTile,
        long stagingDeadline)
    {
        this.matchId = matchId;
        this.regionId = regionId;
        this.host = host;
        this.myDisplayName = myDisplayName;
        this.opponentDisplayName = opponentDisplayName;
        this.myNormalized = NameUtil.normalize(myDisplayName);
        this.opponentNormalized = NameUtil.normalize(opponentDisplayName);
        this.myAssignedTile = myAssignedTile;
        this.opponentAssignedTile = opponentAssignedTile;
        this.stagingDeadline = stagingDeadline;
        this.state = State.STAGING;
        this.scores.put(myDisplayName, 0);
        this.scores.put(opponentDisplayName, 0);
    }

    /**
     * Map a wire-payload key (which may be normalized OR display-name)
     * back to one of our two display-name keys. Returns null if neither
     * matches (shouldn't happen — defends against server drift).
     */
    private String resolveDisplayName(String wireKey)
    {
        if (wireKey == null) return null;
        if (wireKey.equals(myDisplayName) || wireKey.equals(opponentDisplayName)) return wireKey;
        String n = NameUtil.normalize(wireKey);
        if (n.equals(myNormalized)) return myDisplayName;
        if (n.equals(opponentNormalized)) return opponentDisplayName;
        return null;
    }

    /**
     * Build a session from an ARENA_STAGED payload. Returns null if the
     * local player's display name isn't one of the keys in `tiles` (which
     * would mean the server staged a match for someone else and we got
     * crosstalk — shouldn't happen, but defend).
     */
    public static MatchSession fromArenaStaged(
        String matchId,
        int regionId,
        HostNpc host,
        Map<String, WorldPoint> tiles,
        long stagingDeadline,
        String myDisplayName)
    {
        if (tiles == null || myDisplayName == null) return null;
        // Case-insensitive lookup: the server may have echoed slightly different casing.
        String myKey = null;
        String otherKey = null;
        for (String k : tiles.keySet())
        {
            if (k.equalsIgnoreCase(myDisplayName))
            {
                myKey = k;
            }
            else
            {
                otherKey = k;
            }
        }
        if (myKey == null || otherKey == null) return null;
        return new MatchSession(
            matchId, regionId, host,
            myKey, otherKey,
            tiles.get(myKey), tiles.get(otherKey),
            stagingDeadline);
    }

    // -- State accessors --------------------------------------------------

    public State getState() { return state; }
    public boolean isLocalReady() { return localReady; }
    public Map<String, Integer> getScores() { return scores; }
    public int getCurrentQuestionIndex() { return currentQuestionIndex; }
    public String getCurrentPrompt() { return currentPrompt; }
    public long getCurrentDeadline() { return currentDeadline; }
    public boolean isQuestionActive() { return !questionResolved && state == State.IN_PROGRESS; }
    public String getLastCorrectDisplay() { return lastCorrectDisplay; }
    public String getLastCanonicalAnswer() { return lastCanonicalAnswer; }

    // -- Mutators (called from the plugin core on the client thread) ------

    public void markLocalReady() { this.localReady = true; }

    public void markStarted(Map<String, Integer> initialScores)
    {
        this.state = State.IN_PROGRESS;
        applyScores(initialScores);
    }

    private void applyScores(Map<String, Integer> incoming)
    {
        if (incoming == null) return;
        for (Map.Entry<String, Integer> e : incoming.entrySet())
        {
            String display = resolveDisplayName(e.getKey());
            if (display == null) continue;
            this.scores.put(display, e.getValue() == null ? 0 : e.getValue());
        }
    }

    public void setCurrentQuestion(int index, String prompt, long deadline)
    {
        this.currentQuestionIndex = index;
        this.currentPrompt = prompt;
        this.currentDeadline = deadline;
        this.questionResolved = false;
        this.lastCorrectDisplay = null;
        this.lastCanonicalAnswer = null;
    }

    /**
     * Apply a QUESTION_RESOLVED. Updates running scores, derives who (if
     * anyone) got the question right from the results map, and marks the
     * question resolved so chat input stops being forwarded.
     *
     * @param results        results keyed by either normalized or display name
     * @param newScores      updated scores keyed by either form
     * @param canonicalAnswer the server's canonical answer (for UI/overhead)
     */
    public void applyResolution(
        Map<String, PerPlayerQuestionResult> results,
        Map<String, Integer> newScores,
        String canonicalAnswer)
    {
        applyScores(newScores);
        String correct = null;
        if (results != null)
        {
            for (Map.Entry<String, PerPlayerQuestionResult> e : results.entrySet())
            {
                PerPlayerQuestionResult r = e.getValue();
                if (r != null && r.correct)
                {
                    correct = resolveDisplayName(e.getKey());
                    break;
                }
            }
        }
        this.lastCanonicalAnswer = canonicalAnswer;
        this.lastCorrectDisplay = correct;
        this.questionResolved = true;
    }

    public void markComplete() { this.state = State.COMPLETE; }

    /** Count one more tick the local player has been outside the arena region. */
    public int incrementOutOfRegion() { return ++outOfRegionTicks; }
    /** Reset the out-of-region counter (called when player is in-region). */
    public void resetOutOfRegion() { outOfRegionTicks = 0; }
    public int getOutOfRegionTicks() { return outOfRegionTicks; }
}

