    name = "RuneTrivia",
    description = "Challenge nearby players to OSRS trivia matches. Connects to api.runetrivia.com.",
    tags = {"trivia", "minigame", "social"}
)
public class RuneTriviaPlugin extends Plugin implements TriviaWsClient.Listener, TriviaPanel.Callbacks
{
    private static final String MENU_OPTION = "Challenge to Trivia";

    // OSRS shared "player emote" animation IDs. These play correctly on any
    // humanoid NPC that uses the human skeleton (which is most of them).
    //
    // If a specific reaction looks wrong in-game (animation IDs sometimes
    // shift across cache revisions), the fastest fix is to swap the integer
    // here. The neighbouring emote IDs (855..875 range) are all stable
    // player-emote animations to pick from.
    private static final int ANIM_BOW = 858;     // welcome at staging (confirmed in-game)
    private static final int ANIM_THINK = 857;   // QUESTION_DELIVERED — hand-on-chin
    private static final int ANIM_CHEER = 862;   // QUESTION_RESOLVED correct / winner (confirmed)
    private static final int ANIM_SHRUG = 860;   // QUESTION_RESOLVED nobody / draw
    private static final int ANIM_LAUGH = 861;   // BANTER taunt
    private static final int ANIM_WAVE = 863;    // goodbye before despawn

    /** Walk-in / walk-out distance (tiles) and duration. South of host. */
    private static final int WALK_OFFSET_TILES = 4;
    private static final long WALK_DURATION_MS = 2_000;

    /**
     * Orange used for the "RuneTrivia:" plugin voice in chat. Distinct from
     *   yellow  — system messages
     *   purple  — trade
     *   red     — RuneLite alerts / valuable drops
     *   green   — clan chat
     *   white   — default chat body
     * Hex tuned to be readable on the default dark chat background.
     */
    private static final Color RUNE_TRIVIA_CHAT = new Color(0xFF8C00);

    @Inject private Client client;
    @Inject private ClientThread clientThread;
    @Inject private ClientToolbar clientToolbar;
    @Inject private RuneTriviaConfig config;
    @Inject private TriviaWsClient wsClient;
    @Inject private ArenaTileFinder tileFinder;
    @Inject private OkHttpClient httpClient;
    @Inject private Gson gson;
    @Inject private ConfigManager configManager;
    @Inject private OverlayManager overlayManager;
    @Inject private TriviaQuestionOverlay questionOverlay;
    @Inject private ArenaTileOverlay arenaTileOverlay;
    @Inject private HostSpeechOverlay speechOverlay;
    @Inject private IncomingChallengeBanner challengeBanner;
    @Inject private HostLines hostLines;
    @Inject private HostNpcRenderer hostNpcRenderer;
    @Inject private com.runetrivia.shame.PlayerOutfitOverride outfitOverride;
    @Inject private net.runelite.client.eventbus.EventBus eventBus;

    private TriviaPanel panel;
    private NavigationButton navButton;
    /** Display name we last challenged; cleared on resolution. */
    private volatile String outgoingTargetDisplay;
    /** Active match (null when not in one). Mutated only on the client thread. */
    private volatile MatchSession activeMatch;
    /** Whether the engine's hint arrow is currently set by us. */
    private boolean hintArrowActive;
    /** Pending incoming challenge id, or null. Set on CHALLENGE_OFFERED, cleared on CHALLENGE_RESOLVED. */
    private volatile String pendingIncomingChallengeId;
    /** Display name of the challenger; used for hint-arrow lookup + banner text. */
    private volatile String pendingIncomingChallengerDisplay;

    @Override
    protected void startUp()
    {
        log.info("RuneTrivia starting up. Backend: {}", config.backendUrl());

        panel = new TriviaPanel();
        panel.setCallbacks(this);
        panel.setAcceptingChallenges(config.acceptingChallenges());

        navButton = NavigationButton.builder()
            .tooltip("RuneTrivia")
            .icon(ImageUtil.loadImageResource(RuneTriviaPlugin.class, "/com/runetrivia/icon.png"))
            .priority(7)
            .panel(panel)
            .build();
        clientToolbar.addNavigation(navButton);

        wsClient.setListener(this);
        // The game-tick handler will start the WS as soon as we're logged in
        // and the localPlayer is populated. Don't try to race that here.

        questionOverlay.setSessionSupplier(() -> activeMatch);
        arenaTileOverlay.setSessionSupplier(() -> activeMatch);
        speechOverlay.setSessionSupplier(() -> activeMatch);
        // Banner only renders when a pending incoming challenge exists AND
        // the config toggle is on.
        challengeBanner.setChallengerSupplier(() ->
            config.showChallengeBanner() ? pendingIncomingChallengerDisplay : null);
        overlayManager.add(questionOverlay);
        overlayManager.add(arenaTileOverlay);
        overlayManager.add(speechOverlay);
        overlayManager.add(challengeBanner);

        // PlayerOutfitOverride listens for PlayerSpawned + GameStateChanged
        // events to keep clown-suit shaming applied. RuneLite's EventBus
        // doesn't auto-discover @Subscribe methods on Singletons — they
        // must be explicitly registered.
        eventBus.register(outfitOverride);

        refreshMatchHistory();
    }

    @Override
    protected void shutDown()
    {
        log.info("RuneTrivia shutting down.");
        wsClient.stop();
        // Clear the hint arrow on the client thread (engine API is game-thread-only).
        clientThread.invoke(() ->
        {
            if (hintArrowActive)
            {
                client.clearHintArrow();
                hintArrowActive = false;
            }
        });
        hostNpcRenderer.requestDespawn();
        overlayManager.remove(questionOverlay);
        overlayManager.remove(arenaTileOverlay);
        overlayManager.remove(speechOverlay);
        overlayManager.remove(challengeBanner);
        eventBus.unregister(outfitOverride);
        clientToolbar.removeNavigation(navButton);
        panel = null;
        navButton = null;
        activeMatch = null;
    }

    @Provides
    RuneTriviaConfig provideConfig(ConfigManager configManager)
    {
        return configManager.getConfig(RuneTriviaConfig.class);
    }

    // -- Game events -------------------------------------------------------

    @Subscribe
    public void onGameStateChanged(GameStateChanged event)
    {
        if (event.getGameState() == GameState.LOGIN_SCREEN || event.getGameState() == GameState.HOPPING)
        {
            // Drop the connection; the game-tick handler will reconnect when we're back in-world.
            wsClient.stop();
        }
    }

    @Subscribe
    public void onGameTick(GameTick event)
    {
        // Defensive auto-(re)connect:
        //   * Handles the LOGGED_IN-before-localPlayer race where startWebsocket
        //     bails because client.getLocalPlayer() hasn't populated yet.
        //   * Idempotent — TriviaWsClient.start() returns immediately if already running.
        if (wsClient.getStatus() == TriviaWsClient.Status.DISCONNECTED
            && client.getGameState() == GameState.LOGGED_IN
            && client.getLocalPlayer() != null
            && client.getLocalPlayer().getName() != null)
        {
            startWebsocket();
        }

        checkAutoReady();
        checkForfeitTriggers();
        updateHintArrow();
        // Retry NPC model spawn until all parts have loaded (loadModelData is
        // async — a freshly logged-in client typically takes 1–3 ticks before
        // it has the model parts in cache).
        hostNpcRenderer.onTick();
        // Expire timed-out shame overrides.
        outfitOverride.tick();
    }

    /**
     * Drive the engine's hint arrow. Two cases:
     *
     *   STAGING — arrow points at the host tile so the local player can find
     *             the arena. Priority over incoming-challenge arrow because
     *             time-critical (auto-ready window).
     *   Pending incoming challenge — arrow points at the challenging player
     *             so the local player can see who's challenging them and
     *             where they are (world + minimap). Cleared on resolution.
     *
     * Uses the engine's setHintArrow APIs (Player overload tracks
     * automatically; WorldPoint overload is static). Engine animates the
     * pulse/blink itself — no custom on/off cycling.
     */
    private void updateHintArrow()
    {
        MatchSession s = activeMatch;
        boolean stagingArrow =
            s != null
            && s.getState() == MatchSession.State.STAGING
            && !s.isLocalReady()
            && s.host != null
            && s.host.tile != null;

        boolean challengeArrow =
            !stagingArrow                         // staging wins if both
            && pendingIncomingChallengeId != null
            && pendingIncomingChallengerDisplay != null
            && config.showChallengerHintArrow();

        boolean shouldShow = stagingArrow || challengeArrow;

        if (shouldShow && !hintArrowActive)
        {
            if (stagingArrow)
            {
                Domain.WorldPoint t = s.host.tile;
                client.setHintArrow(
                    new net.runelite.api.coords.WorldPoint(t.x, t.y, t.plane));
                hintArrowActive = true;
            }
            else
            {
                Player challenger = findPlayerByDisplay(pendingIncomingChallengerDisplay);
                if (challenger != null)
                {
                    client.setHintArrow(challenger);
                    hintArrowActive = true;
                }
                // If challenger isn't in render distance, the arrow simply
                // doesn't appear — the chat line + banner still convey the
                // notification. Next tick will retry if they enter range.
            }
        }
        else if (!shouldShow && hintArrowActive)
        {
            client.clearHintArrow();
            hintArrowActive = false;
        }
    }

    /**
     * Find a Player in the local render distance by display name. Returns
     * null if the player is offscreen / unloaded — the hint arrow simply
     * won't render until they enter range (and updateHintArrow re-evaluates
     * each GameTick).
     */
    private Player findPlayerByDisplay(String displayName)
    {
        if (displayName == null) return null;
        String norm = com.runetrivia.util.NameUtil.normalize(displayName);
        for (Player p : client.getPlayers())
        {
            if (p == null || p.getName() == null) continue;
            if (com.runetrivia.util.NameUtil.normalize(p.getName()).equals(norm)) return p;
        }
        return null;
    }

    @Subscribe
    public void onClientTick(ClientTick event)
    {
        // High-frequency hook (~20ms) used for smooth walk interpolation.
        // GameTick (600ms) is too coarse — the host would teleport between
        // tiles in 3-4 jumps over a 2s walk. ClientTick gives ~100 updates
        // for the same span, so the model glides.
        hostNpcRenderer.onClientTick();
    }

    /**
     * Forfeit triggers (per LESSONS.md):
     *   * Region ID differs from arena region for 3 consecutive ticks
     *     (3-tick tolerance for transient teleport/pathing).
     *   * Local player enters an instanced region.
     *   * (Logout / hop / disconnect are handled server-side via dropPlayer
     *     when the WS closes — we don't need to fire MATCH_FORFEIT for those.)
     */
    private void checkForfeitTriggers()
    {
        MatchSession session = activeMatch;
        if (session == null) return;
        if (session.getState() == MatchSession.State.COMPLETE) return;
        Player me = client.getLocalPlayer();
        if (me == null) return;
        net.runelite.api.coords.WorldPoint wp = me.getWorldLocation();
        if (wp == null) return;

        if (client.isInInstancedRegion())
        {
            log.info("forfeiting {}: entered instanced region", session.matchId);
            sendForfeit(session.matchId, "LEFT_ARENA");
            return;
        }
        if (wp.getRegionID() != session.regionId)
        {
            int ticks = session.incrementOutOfRegion();
            if (ticks >= 3)
            {
                log.info("forfeiting {}: out of region for {} ticks (mine={}, arena={})",
                    session.matchId, ticks, wp.getRegionID(), session.regionId);
                sendForfeit(session.matchId, "LEFT_ARENA");
            }
        }
        else
        {
            session.resetOutOfRegion();
        }
    }

    private void sendForfeit(String matchId, String reason)
    {
        Messages.MatchForfeitPayload p = new Messages.MatchForfeitPayload();
        p.matchId = matchId;
        p.reason = reason;
        wsClient.send(Messages.TYPE_MATCH_FORFEIT, p);
    }

    /**
     * During STAGING, send PLAYER_READY as soon as the local player steps
     * inside the arena radius around the host NPC. The radius is also drawn
     * on the ground by {@link com.runetrivia.ui.ArenaTileOverlay} so players
     * have a clear visual target.
     *
     * Idempotent — guarded by {@code MatchSession#isLocalReady()}.
     */
    private void checkAutoReady()
    {
        MatchSession session = activeMatch;
        if (session == null
            || session.getState() != MatchSession.State.STAGING
            || session.isLocalReady())
        {
            return;
        }
        if (session.host == null || session.host.tile == null) return;
        Player me = client.getLocalPlayer();
        if (me == null) return;
        net.runelite.api.coords.WorldPoint wp = me.getWorldLocation();
        if (wp == null) return;
        Domain.WorldPoint hostTile = session.host.tile;
        if (wp.getPlane() != hostTile.plane) return;
        int dx = Math.abs(wp.getX() - hostTile.x);
        int dy = Math.abs(wp.getY() - hostTile.y);
        if (Math.max(dx, dy) > MatchSession.ARENA_RADIUS) return;

        session.markLocalReady();
        Messages.PlayerReadyPayload p = new Messages.PlayerReadyPayload();
        p.matchId = session.matchId;
        wsClient.send(Messages.TYPE_PLAYER_READY, p);
        log.info("sent PLAYER_READY for {} (inside arena radius)", session.matchId);
        renderActiveMatchPanel();
    }

    @Subscribe
    public void onMenuEntryAdded(MenuEntryAdded event)
    {
        if (!config.enableRightClickChallenge())
        {
            return;
        }
        // If the user has opted into "shift-only" mode, hide the entry from
        // the regular right-click menu and only inject it when shift is
        // held. KC_SHIFT covers both left + right shift keys.
        if (config.challengeMenuRequiresShift()
            && !client.isKeyPressed(net.runelite.api.KeyCode.KC_SHIFT))
        {
            return;
        }
        MenuEntry entry = event.getMenuEntry();
        if (entry == null)
        {
            return;
        }
        // Filter by option text rather than MenuAction enum value: the PLAYER_*_OPTION
        // type-numbering shifts depending on whether "Attack" is present (PvP world,
        // wilderness, etc.). "Follow" is reliably present on player right-clicks
        // everywhere and gives us a single dedupe trigger.
        if (!"Follow".equalsIgnoreCase(entry.getOption()))
        {
            return;
        }
        Player target = entry.getPlayer();
        if (target == null || target == client.getLocalPlayer())
        {
            return;
        }

        // Add normally here; the actual "move to bottom" happens in
        // onPostMenuSort below. setDeprioritized turned out NOT to
        // reorder RUNELITE_PLAYER entries — it only changes the visual
        // styling. Direct array manipulation in PostMenuSort is what
        // actually works.
        client.createMenuEntry(-1)
            .setOption(MENU_OPTION)
            .setTarget(entry.getTarget())
            .setType(MenuAction.RUNELITE_PLAYER)
            .setIdentifier(entry.getIdentifier())
            .onClick(e -> initiateChallenge(target.getName()));
    }

    /**
     * Move our "Challenge to Trivia" entry to the bottom of the right-click
     * menu (just above Cancel). PostMenuSort fires after the engine has
     * finished sorting entries, just before render — that's the safest
     * point to reorder without fighting the engine's own sort.
     *
     * Menu-array convention in RuneLite:
     *   index 0       = Cancel (always at bottom of visual menu)
     *   index 1       = bottom-most action (next slot above Cancel)
     *   index n-1     = top-most action
     *
     * So to put our entry "at the bottom of actions," we want it at
     * index 1. We find it by MENU_OPTION text, remove it, and re-insert
     * at index 1, shifting everything between up by one.
     *
     * Why setDeprioritized() didn't work: that flag is honored by the
     * engine for certain native MenuAction types (it's what makes the
     * gray "Walk here" sort to the top), but for RUNELITE_PLAYER (our
     * plugin-injected type), the engine doesn't apply the deprioritize
     * sort. Manual reorder it is.
     */
    @Subscribe
    public void onPostMenuSort(PostMenuSort event)
    {
        MenuEntry[] entries = client.getMenuEntries();
        // Find our entry. Searching by MENU_OPTION text is robust — we
        // don't have a stable identifier on the entry itself.
        int ourIdx = -1;
        for (int i = 0; i < entries.length; i++)
        {
            if (MENU_OPTION.equals(entries[i].getOption()))
            {
                ourIdx = i;
                break;
            }
        }
        // Not present (e.g. right-click target wasn't a player), or
        // already at the bottom-most action slot.
        if (ourIdx <= 1) return;

        MenuEntry ours = entries[ourIdx];
        MenuEntry[] reordered = new MenuEntry[entries.length];
        reordered[0] = entries[0];      // Cancel stays at 0
        reordered[1] = ours;            // our entry slots in above Cancel
        // Everything between original [1..ourIdx-1] shifts up by one.
        int dst = 2;
        for (int i = 1; i < entries.length; i++)
        {
            if (i == ourIdx) continue;
            reordered[dst++] = entries[i];
        }
        client.setMenuEntries(reordered);
    }

    @Subscribe
    public void onChatMessage(ChatMessage event)
    {
        // Players type free-text answers in public chat. We forward chat from
        // the local player while a question is active. The chat still renders
        // normally — that's the social/banter point. Non-matching text is
        // discarded server-side as banter.
        if (event.getType() != ChatMessageType.PUBLICCHAT) return;
        MatchSession session = activeMatch;
        if (session == null || !session.isQuestionActive()) return;
        Player me = client.getLocalPlayer();
        if (me == null || me.getName() == null) return;
        // ChatMessage#getName carries the sender's display name; OSRS may
        // embed NBSP, so normalize before comparing.
        if (!com.runetrivia.util.NameUtil.normalize(event.getName())
                .equals(com.runetrivia.util.NameUtil.normalize(me.getName())))
        {
            return;
        }
        String text = event.getMessage();
        if (text == null || text.isEmpty()) return;

        Messages.AnswerSubmitPayload p = new Messages.AnswerSubmitPayload();
        p.matchId = session.matchId;
        p.questionIndex = session.getCurrentQuestionIndex();
        p.text = text;
        wsClient.send(Messages.TYPE_ANSWER_SUBMIT, p);
        log.debug("forwarded answer for q{}: {}", p.questionIndex, text);
    }

    /**
     * Handle ::accept / ::decline / ::forfeit (and their rt-prefixed
     * variants). CommandExecuted fires on the client thread when the local
     * player types a `::cmd` in the chat input — the message is consumed
     * by the engine and never goes out as public chat.
     *
     * Each command no-ops gracefully when the relevant precondition isn't
     * met (no pending challenge for accept/decline, no active match for
     * forfeit). This makes the commands safe even if another plugin
     * registers the same name — both handlers run, ours just does
     * nothing when our state is empty.
     */
    @Subscribe
    public void onCommandExecuted(CommandExecuted event)
    {
        String cmd = event.getCommand();
        if (cmd == null) return;
        String c = cmd.toLowerCase();
        switch (c)
        {
            case "accept":
            case "rtaccept":
                respondToPendingChallenge(true);
                return;
            case "decline":
            case "rtdecline":
                respondToPendingChallenge(false);
                return;
            case "forfeit":
            case "rtforfeit":
                if (activeMatch == null)
                {
                    chatNote("No active match to forfeit.");
                    return;
                }
                sendForfeit("user_forfeit");
                chatNote("Forfeit sent.");
                return;
            case "tsfx":
                handleSoundTestCommand(event.getArguments());
                return;
            case "tsfxnext":
                stepSoundTest(+1);
                return;
            case "tsfxprev":
                stepSoundTest(-1);
                return;
            case "wiki":
                // Jagex-native command. We don't consume it (the engine
                // still opens the wiki) but we observe it for anti-cheat.
                if (activeMatch != null)
                {
                    reportWikiTrigger("wiki_chat_command");
                }
                return;
            default:
                // not one of ours; ignore
        }
    }

    /**
     * Step the sound-test cursor by {@code delta} (+1 / -1) and play the
     * new ID. Lets the user sweep through ID ranges with single short
     * commands instead of retyping numbers. If no ::tsfx has been run yet,
     * starts at 1 (going up) or 1 (going down — clamped to positive).
     */
    private void stepSoundTest(int delta)
    {
        int next = lastSoundTestId + delta;
        if (next < 1) next = 1;
        try
        {
            client.playSoundEffect(next);
            lastSoundTestId = next;
            chatNote("Played sound " + next + ".");
        }
        catch (Exception e)
        {
            chatNote("::tsfx " + next + " threw: " + e.toString());
        }
    }

    /**
     * ::tsfx &lt;id&gt; — play an OSRS sound effect by ID, locally, in the
     * game's actual audio mix. Lets the user sweep candidate IDs without
     * editing config or restarting. Echoes the ID back so they can track
     * which one they just heard.
     *
     * Usage:
     *   ::tsfx 1444       play sound 1444
     *   ::tsfx            re-play the last one (or 0 if none yet)
     */
    private int lastSoundTestId = 0;
    private void handleSoundTestCommand(String[] args)
    {
        int id;
        if (args == null || args.length == 0 || args[0].isEmpty())
        {
            id = lastSoundTestId;
            if (id <= 0)
            {
                chatNote("::tsfx usage: type '::tsfx 1444' to play sound 1444.");
                return;
            }
        }
        else
        {
            try { id = Integer.parseInt(args[0]); }
            catch (NumberFormatException nfe)
            {
                chatNote("::tsfx: '" + args[0] + "' is not a number.");
                return;
            }
        }
        if (id <= 0)
        {
            chatNote("::tsfx: id must be a positive integer.");
            return;
        }
        try
        {
            client.playSoundEffect(id);
            lastSoundTestId = id;
            chatNote("Played sound " + id + ".");
        }
        catch (Exception e)
        {
            chatNote("::tsfx " + id + " threw: " + e.toString());
        }
    }

    /** Shared helper for the ::accept / ::decline commands. */
    private void respondToPendingChallenge(boolean accept)
    {
        String challengeId = pendingIncomingChallengeId;
        if (challengeId == null)
        {
            chatNote("No pending challenge to " + (accept ? "accept" : "decline") + ".");
            return;
        }
        onChallengeResponse(challengeId, accept);
    }

    /** Quick echo-back message for chat-command feedback. */
    private void chatNote(String msg)
    {
        // Same orange the challenge notification uses — consistent "this is
        // the RuneTrivia plugin talking" voice across all our chat output.
        String formatted = new ChatMessageBuilder()
            .append(RUNE_TRIVIA_CHAT, "RuneTrivia: " + msg)
            .build();
        client.addChatMessage(ChatMessageType.GAMEMESSAGE, "", formatted, null);
    }

    @Subscribe
    public void onConfigChanged(ConfigChanged event)
    {
        if (!"runetrivia".equals(event.getGroup()))
        {
            return;
        }
        if ("acceptingChallenges".equals(event.getKey()))
        {
            wsClient.updateAcceptingChallenges(config.acceptingChallenges());
            panel.setAcceptingChallenges(config.acceptingChallenges());
        }
    }

    // -- Anti-cheat: wiki detection ---------------------------------------
    //
    // Zero-tolerance: any wiki interaction during an active match triggers
    // an immediate server-side forfeit + clown-suit shame. We detect three
    // surfaces:
    //
    //   1. RuneLite Wiki plugin's right-click menu options ("Wiki",
    //      "Lookup") — onMenuOptionClicked
    //   2. The in-game wiki search widget — onWidgetLoaded
    //   3. The ::wiki chat command (Jagex-native) — onCommandExecuted
    //
    // Each path calls reportWikiTrigger(source) which guards against
    // duplicate firing within a single match.

    /** Widget group ID for the in-game wiki search interface. */
    private static final int WIKI_SEARCH_WIDGET_GROUP_ID = 791;

    /** Whether we've already fired WIKI_TRIGGERED for the current match. Reset on match start. */
    private volatile boolean wikiTriggeredForCurrentMatch;

    @Subscribe
    public void onMenuOptionClicked(MenuOptionClicked event)
    {
        if (activeMatch == null) return;

        // Path 1: RuneLite Wiki plugin menu options.
        // The Wiki plugin uses "Lookup" with target containing "Wiki",
        // and some menus add a bare "Wiki" option. Match both case-insensitively.
        String option = event.getMenuOption();
        String target = event.getMenuTarget();
        if (option != null)
        {
            String lo = option.toLowerCase();
            boolean isWikiMenu = lo.contains("wiki")
                || (lo.equals("lookup") && target != null && target.toLowerCase().contains("wiki"));
            if (isWikiMenu)
            {
                reportWikiTrigger("runelite_wiki_menu");
                return;
            }
        }

        // Path 2: any click on a widget inside the in-game wiki interface.
        // Catches the Search button, result links, etc. — anything beyond
        // just opening the panel. getParam1() is the packed widget ID; the
        // high 16 bits are the widget group, low 16 are the child index.
        int widgetGroupId = event.getParam1() >>> 16;
        if (widgetGroupId == WIKI_SEARCH_WIDGET_GROUP_ID)
        {
            reportWikiTrigger("in_game_wiki_widget");
        }
    }

    @Subscribe
    public void onWidgetLoaded(WidgetLoaded event)
    {
        if (activeMatch == null) return;
        if (event.getGroupId() == WIKI_SEARCH_WIDGET_GROUP_ID)
        {
            reportWikiTrigger("in_game_wiki_widget");
        }
    }

    /**
     * Fire WIKI_TRIGGERED to the server. Idempotent per-match — repeated
     * triggers in the same match are no-ops (the server already started
     * forfeiting; further events are noise).
     */
    private void reportWikiTrigger(String source)
    {
        MatchSession session = activeMatch;
        if (session == null) return;
        if (wikiTriggeredForCurrentMatch) return;
        wikiTriggeredForCurrentMatch = true;

        Messages.WikiTriggeredPayload p = new Messages.WikiTriggeredPayload();
        p.matchId = session.matchId;
        p.source = source;
        wsClient.send(Messages.TYPE_WIKI_TRIGGERED, p);
        log.info("WIKI_TRIGGERED sent for match {} (source={})", session.matchId, source);
        chatNote("You triggered the wiki during a match. Forfeiting!");
    }

    // -- Outgoing challenge -----------------------------------------------

    private void initiateChallenge(String targetDisplayName)
    {
        if (targetDisplayName == null || targetDisplayName.isEmpty())
        {
            return;
        }
        // ArenaTileFinder reads CollisionData / scene state, which is only
        // reliable from the game thread. Button clicks arrive on the EDT and
        // menu-entry onClick callbacks may also be off-thread, so we marshal
        // both paths through ClientThread.invoke().
        clientThread.invoke(() ->
        {
            Domain.ArenaProposal arena = tileFinder.findArena();
            Domain.WorldPoint loc = tileFinder.currentLocation();
            if (arena == null || loc == null)
            {
                log.warn("could not find an arena tile near the player (target={})", targetDisplayName);
                return;
            }
            log.info("sending CHALLENGE_CREATE for target={} region={}", targetDisplayName, arena.regionId);
            Messages.ChallengeCreatePayload payload = new Messages.ChallengeCreatePayload();
            payload.targetDisplayName = targetDisplayName;
            payload.challengerLocation = loc;
            payload.proposedArena = arena;
            outgoingTargetDisplay = targetDisplayName;
            panel.renderOutgoing(targetDisplayName, "Challenge sent. Waiting for response…");
            wsClient.send(Messages.TYPE_CHALLENGE_CREATE, payload);
        });
    }

