    /**
     * Send MATCH_FORFEIT to the server. Used by both the side-panel button
     * and the ::forfeit chat command. No-op when there's no active match.
     */
    private void sendForfeit(String reason)
    {
        MatchSession s = activeMatch;
        if (s == null || s.matchId == null) return;
        Messages.MatchForfeitPayload p = new Messages.MatchForfeitPayload();
        p.matchId = s.matchId;
        p.reason = reason;
        wsClient.send(Messages.TYPE_MATCH_FORFEIT, p);
        log.info("local forfeit sent for match {} (reason={})", s.matchId, reason);
    }

