    }

    @Override
    public void onMessage(String type, String id, JsonElement payload)
    {
        switch (type)
        {
            case Messages.TYPE_CHALLENGE_OFFERED:
            {
                Messages.ChallengeOfferedPayload p = gson.fromJson(payload, Messages.ChallengeOfferedPayload.class);
                handleIncomingChallenge(p);
                return;
            }
            case Messages.TYPE_CHALLENGE_RESOLVED:
            {
                Messages.ChallengeResolvedPayload p = gson.fromJson(payload, Messages.ChallengeResolvedPayload.class);
                handleChallengeResolved(p);
                return;
            }
            case Messages.TYPE_ARENA_STAGED:
            {
                Messages.ArenaStagedPayload p = gson.fromJson(payload, Messages.ArenaStagedPayload.class);
                handleArenaStaged(p);
                return;
            }
            case Messages.TYPE_MATCH_STARTED:
            {
                Messages.MatchStartedPayload p = gson.fromJson(payload, Messages.MatchStartedPayload.class);
                handleMatchStarted(p);
                return;
            }
            case Messages.TYPE_QUESTION_DELIVERED:
            {
                Messages.QuestionDeliveredPayload p = gson.fromJson(payload, Messages.QuestionDeliveredPayload.class);
                handleQuestionDelivered(p);
                return;
            }
            case Messages.TYPE_QUESTION_RESOLVED:
            {
                Messages.QuestionResolvedPayload p = gson.fromJson(payload, Messages.QuestionResolvedPayload.class);
                handleQuestionResolved(p);
                return;
            }
            case Messages.TYPE_MATCH_COMPLETED:
            {
                Messages.MatchCompletedPayload p = gson.fromJson(payload, Messages.MatchCompletedPayload.class);
                handleMatchCompleted(p);
                return;
            }
            case Messages.TYPE_MATCH_FORFEIT:
            {
                Messages.MatchForfeitPayload p = gson.fromJson(payload, Messages.MatchForfeitPayload.class);
                handleMatchForfeit(p);
                return;
            }
            case Messages.TYPE_BANTER:
            {
                Messages.BanterPayload p = gson.fromJson(payload, Messages.BanterPayload.class);
                handleBanter(p);
                return;
            }
            case Messages.TYPE_SHAME_PLAYER:
            {
                Messages.ShamePlayerPayload p = gson.fromJson(payload, Messages.ShamePlayerPayload.class);
                handleShamePlayer(p);
                return;
            }
            case Messages.TYPE_CHALLENGE_CREATED:
            case Messages.TYPE_WELCOME:
            case Messages.TYPE_PONG:
            case Messages.TYPE_ERROR:
                // Status / confirmation frames; nothing actionable here.
                return;
            default:
                log.debug("unhandled message type: {}", type);
        }
    }

    private void handleIncomingChallenge(Messages.ChallengeOfferedPayload p)
    {
        // We arrive here on the OkHttp dispatcher thread (from WS onMessage).
        // Local range validation reads client.getLocalPlayer().getWorldLocation(),
        // which RuneLite enforces as client-thread-only (assertion failure off-thread).
        clientThread.invoke(() ->
        {
            Player me = client.getLocalPlayer();
            if (me != null && me.getWorldLocation() != null
                && p.proposedArena != null
                && me.getWorldLocation().getRegionID() != p.proposedArena.regionId)
            {
                log.info("auto-declining challenge {}: not in same region (mine={}, theirs={})",
                    p.challengeId, me.getWorldLocation().getRegionID(), p.proposedArena.regionId);
                Messages.ChallengeRespondPayload reply = new Messages.ChallengeRespondPayload();
                reply.challengeId = p.challengeId;
                reply.accept = false;
                wsClient.send(Messages.TYPE_CHALLENGE_RESPOND, reply);
                return;
            }
            // Track the pending challenge so the banner overlay, hint arrow,
            // and ::accept/::decline chat commands all have something to act on.
            pendingIncomingChallengeId = p.challengeId;
            pendingIncomingChallengerDisplay = p.fromDisplayName;
            panel.renderPending(p.challengeId, p.fromDisplayName);

            // Chat-line baseline notification. Always on — non-aggressive and
            // persists in chat history for later review. Orange to differentiate
            // from the other chat color slots (yellow=system, purple=trade,
            // red=RuneLite alerts, green=clan, white=default).
            String formatted = new ChatMessageBuilder()
                .append(RUNE_TRIVIA_CHAT,
                    "RuneTrivia: " + p.fromDisplayName
                    + " has challenged you to a match! "
                    + "Open the side panel or type ::accept / ::decline.")
                .build();
            client.addChatMessage(ChatMessageType.GAMEMESSAGE, "", formatted, null);

            // Soft chime (config-gated). Plays locally only — no broadcast.
            if (config.playChallengeChime())
            {
                playSfx(config.challengeChimeId());
            }
            // updateHintArrow runs every GameTick and will pick up the new
            // pendingIncomingChallengerDisplay on its next pass.
        });
    }

    private void handleChallengeResolved(Messages.ChallengeResolvedPayload p)
    {
        panel.renderPending(null, null);
        // Clear pending-incoming state so the banner overlay vanishes and
        // the next updateHintArrow tick clears the arrow.
        if (p.challengeId != null && p.challengeId.equals(pendingIncomingChallengeId))
        {
            pendingIncomingChallengeId = null;
            pendingIncomingChallengerDisplay = null;
        }
        log.info("challenge {} resolved: accepted={} reason={}",
            p.challengeId, p.accepted, p.reason);

        // Only update the outgoing-challenge panel if we have one in flight.
        // (CHALLENGE_RESOLVED is broadcast to both parties, so we'd otherwise
        // clobber the incoming side with the outgoing label.)
        if (outgoingTargetDisplay != null)
        {
            String target = outgoingTargetDisplay;
            String msg;
            if (p.accepted)
            {
                msg = "Challenge accepted! Match starting…";
            }
            else
            {
                msg = "Challenge ended: " + humanReason(p.reason);
            }
            panel.renderOutgoing(target, msg);
            outgoingTargetDisplay = null;
            // Auto-clear the panel after a few seconds so it doesn't sit stale.
            new java.util.Timer(true).schedule(new java.util.TimerTask()
            {
                @Override
                public void run()
                {
                    if (panel != null)
                    {
                        panel.renderOutgoing(null, null);
                    }
                }
            }, 6000);
        }
        // TODO: phase 4 — if accepted, transition to staging UI.
    }

    // -- Match lifecycle handlers (Phase 4) -------------------------------

    private void handleArenaStaged(Messages.ArenaStagedPayload p)
    {
        // Touches client.getLocalPlayer() and stores per-tile data we'll
        // later read from the game thread; do all of it under the client thread.
        clientThread.invoke(() ->
        {
            Player me = client.getLocalPlayer();
            String myDisplay = me == null ? null : me.getName();
            if (myDisplay == null)
            {
                log.warn("ARENA_STAGED arrived but local player not loaded; can't bind match");
                return;
            }
            MatchSession session = MatchSession.fromArenaStaged(
                p.matchId, p.regionId, p.host, p.tiles, p.stagingDeadline, myDisplay);
            if (session == null)
            {
                log.warn("ARENA_STAGED tiles did not include local player {} (keys={})",
                    myDisplay, p.tiles == null ? "null" : p.tiles.keySet());
                return;
            }
            activeMatch = session;
            // Outgoing-challenge UI is no longer relevant once we're staging.
            outgoingTargetDisplay = null;
            panel.renderOutgoing(null, null);
            renderActiveMatchPanel();
            log.info("match {} staged in region {}; my tile={} opponent tile={}",
                p.matchId, p.regionId, session.myAssignedTile, session.opponentAssignedTile);
            // Try to spawn the visible NPC (gated by config). Retries happen
            // every GameTick until the model parts have loaded.
            if (config.showHostNpc() && session.host != null && session.host.tile != null)
            {
                // Per-NPC idle / walk animation overrides via host_lines JSON.
                int idleAnim = hostLines.getInt(
                    session.host.displayName, "idleAnimation", HostNpcRenderer.DEFAULT_IDLE_ANIM);
                int walkAnim = hostLines.getInt(
                    session.host.displayName, "walkAnimation", HostNpcRenderer.DEFAULT_WALK_ANIM);
                hostNpcRenderer.setIdleAnimation(idleAnim);
                hostNpcRenderer.setWalkAnimation(walkAnim);
                // Spawn off-arena and walk in. The host "arrives" rather than
                // pops into existence on the host tile. Bow + welcome line
                // both fire once they're standing on the final tile — the
                // text used to appear mid-walk, which broke the illusion that
                // the host is the one speaking.
                Domain.WorldPoint dest = session.host.tile;
                Domain.WorldPoint walkInFrom = walkInOriginFor(dest);
                hostNpcRenderer.requestSpawn(session.host.npcId, walkInFrom);
                // Bow + welcome fire exactly when the host arrives — the
                // callback runs on the client thread from advanceWalkSegment,
                // so no Timer race with the walk's actual completion.
                hostNpcRenderer.walkTo(dest, () ->
                {
                    hostNpcRenderer.playReaction(ANIM_BOW, 1_000);
                    sayCategory("welcome", null);
                });
            }
            else
            {
                // No host NPC configured — say it immediately so the player
                // still sees the welcome line.
                sayCategory("welcome", null);
            }
        });
    }

    private void handleMatchStarted(Messages.MatchStartedPayload p)
    {
        clientThread.invoke(() ->
        {
            MatchSession session = activeMatch;
            if (session == null || !p.matchId.equals(session.matchId)) return;
            session.markStarted(null);
            // Fresh match = fresh wiki-trigger budget. (We don't want the
            // previous match's trigger to suppress detection in this one.)
            wikiTriggeredForCurrentMatch = false;
            renderActiveMatchPanel();
            log.info("match {} started", p.matchId);
            Map<String, String> getReadyVars = new HashMap<>();
            getReadyVars.put("opponent1", session.myDisplayName);
            getReadyVars.put("opponent2", session.opponentDisplayName);
            // The server fires MATCH_STARTED the moment both players are
            // ready, which is typically ~1s into a ~3s host walk-in. Saying
            // "get ready" while the host is still mid-stride breaks the
            // illusion that the host is the one speaking — defer it until
            // they've planted their feet.
            hostNpcRenderer.whenArrived(() -> sayCategory("getReady", getReadyVars));
        });
    }

    private void handleQuestionDelivered(Messages.QuestionDeliveredPayload p)
    {
        clientThread.invoke(() ->
        {
            MatchSession session = activeMatch;
            if (session == null || !p.matchId.equals(session.matchId)) return;
            log.info("question {} delivered: {}", p.questionIndex, p.prompt);
            Map<String, String> qVars = new HashMap<>();
            qVars.put("q", String.valueOf(p.questionIndex + 1));
            String intro = hostLines.pick(hostName(), "questionIntro", qVars);
            // The intro is a brief flavor lead-in; we always append the actual
            // prompt below so the player can read it from the bubble too (the
            // overlay banner shows it for the full 30s).
            String bubble = (intro == null || intro.isEmpty())
                ? "Question " + (p.questionIndex + 1) + ": " + p.prompt
                : intro + "\n" + p.prompt;
            // Defer the on-screen banner + reaction + sound until the host
            // actually starts saying the line. Without this, QUESTION_DELIVERED
            // races ahead of the host's speech queue (welcome → getReady →
            // intro) and the question appears mid-walk-in monologue. The
            // overlay's say(line, onInstalled) fires the callback the moment
            // this line becomes the visible one.
            //
            // Trade-off: a small slice of the server-side response deadline
            // (~5s for the first question of the match) is consumed by the
            // host's intro sequence. Acceptable for the cinematic pacing;
            // can be reclaimed by adding a server-side first-question delay
            // later if needed.
            hostSay(bubble, () -> clientThread.invoke(() ->
            {
                MatchSession s2 = activeMatch;
                if (s2 == null || !p.matchId.equals(s2.matchId)) return;
                s2.setCurrentQuestion(p.questionIndex, p.prompt, p.deadline);
                renderActiveMatchPanel();
                hostNpcRenderer.playReaction(ANIM_THINK, 2_500);
                playSfx(config.questionSoundId());
            }));
        });
    }

    private void handleQuestionResolved(Messages.QuestionResolvedPayload p)
    {
        clientThread.invoke(() ->
        {
            MatchSession session = activeMatch;
            if (session == null || !p.matchId.equals(session.matchId)) return;
            session.applyResolution(p.results, p.scores, p.canonicalAnswer);
            renderActiveMatchPanel();
            log.info("question {} resolved: canonical={} correct={}",
                p.questionIndex, p.canonicalAnswer, session.getLastCorrectDisplay());
            String correct = session.getLastCorrectDisplay();
            Map<String, String> resVars = new HashMap<>();
            resVars.put("answer", p.canonicalAnswer == null ? "" : p.canonicalAnswer);
            if (correct != null)
            {
                resVars.put("player", correct);
                sayCategory("correctReaction", resVars);
                hostNpcRenderer.playReaction(ANIM_CHEER, 2_500);
                playSfx(config.correctSoundId());
            }
            else
            {
                sayCategory("noOneGot", resVars);
                hostNpcRenderer.playReaction(ANIM_SHRUG, 2_500);
            }
        });
    }

    /**
     * Play a sound effect by ID, swallowing any exception. id <= 0 is a
     * no-op so users can disable sounds by clearing the config field.
     * Must be called on the client thread.
     */
    private void playSfx(int id)
    {
        if (id <= 0) return;
        try { client.playSoundEffect(id); }
        catch (Exception e) { log.debug("playSoundEffect({}) threw: {}", id, e.toString()); }
    }

    private void handleMatchCompleted(Messages.MatchCompletedPayload p)
    {
        clientThread.invoke(() ->
        {
            MatchSession session = activeMatch;
            if (session == null || !p.matchId.equals(session.matchId)) return;
            session.markComplete();
            renderActiveMatchPanel();
            log.info("match {} complete: winner={} reason={}",
                p.matchId, p.winnerDisplayName, p.reason);
            Map<String, String> endVars = new HashMap<>();
            if (p.winnerDisplayName != null)
            {
                endVars.put("winner", p.winnerDisplayName);
                String loser = p.winnerDisplayName.equalsIgnoreCase(session.myDisplayName)
                    ? session.opponentDisplayName : session.myDisplayName;
                endVars.put("loser", loser);
                sayCategory("winnerCelebration", endVars);
                hostNpcRenderer.playReaction(ANIM_CHEER, 3_000);
                if (config.playWinnerCelebration())
                {
                    celebrateWinner(p.winnerDisplayName);
                }
            }
            else
            {
                endVars.put("opponent1", session.myDisplayName);
                endVars.put("opponent2", session.opponentDisplayName);
                sayCategory("draw", endVars);
                hostNpcRenderer.playReaction(ANIM_SHRUG, 3_000);
            }
            refreshMatchHistory();
            // Farewell sequence: cheer/shrug (3s) -> wave (1.5s) ->
            // walk away off the arena (2s) -> despawn. Total ~6.5s.
            // Gives the host a grounded exit instead of vanishing in place.
            scheduleHostExit(session.host == null ? null : session.host.tile);
            scheduleClearActiveMatch(p.matchId);
        });
    }

    private void handleMatchForfeit(Messages.MatchForfeitPayload p)
    {
        clientThread.invoke(() ->
        {
            MatchSession session = activeMatch;
            if (session == null || !p.matchId.equals(session.matchId)) return;
            session.markComplete();
            renderActiveMatchPanel();
            log.info("match {} forfeited: {}", p.matchId, p.reason);
            hostSay("The match has been forfeited (" + p.reason + ").");
            // Forfeit is a "things ended awkwardly" moment — keep the NPC for
            // a brief beat then despawn (no celebration animation).
            scheduleDespawnHost(2_000);
            refreshMatchHistory();
            scheduleClearActiveMatch(p.matchId);
        });
    }

    /**
     * Trigger the OSRS level-up fireworks graphic + chime over the named
     * winner. Both clients call this independently; each one looks up the
     * winner among its locally cached players. If the winner isn't in render
     * distance (e.g. they walked off), the graphic silently no-ops but the
     * chime still plays — so the local player at least hears the win state.
     *
     * Must be called on the client thread (the MATCH_COMPLETED handler is
     * already wrapped).
     */
    private void celebrateWinner(String winnerDisplayName)
    {
        // OSRS shared IDs. Both stable across cache revisions.
        final int LEVEL_UP_GRAPHIC = 199;          // firework burst
        final int LEVEL_UP_GRAPHIC_HEIGHT = 84;    // about head-height for a player
        final int LEVEL_UP_SOUND = 2396;           // level-up jingle

        // Local chime so we hear the win regardless of camera position.
        try { client.playSoundEffect(LEVEL_UP_SOUND); }
        catch (Exception e) { log.debug("playSoundEffect threw: {}", e.toString()); }

        // Find the winner among visible players and fire fireworks over them.
        String winnerNorm = com.runetrivia.util.NameUtil.normalize(winnerDisplayName);
        for (Player p : client.getPlayers())
        {
            if (p == null || p.getName() == null) continue;
            if (!com.runetrivia.util.NameUtil.normalize(p.getName()).equals(winnerNorm)) continue;
            try
            {
                p.setGraphic(LEVEL_UP_GRAPHIC);
                p.setGraphicHeight(LEVEL_UP_GRAPHIC_HEIGHT);
                p.setSpotAnimFrame(0);
            }
            catch (Exception e)
            {
                log.debug("setGraphic threw for winner {}: {}", winnerDisplayName, e.toString());
            }
            log.info("celebrating winner {} with fireworks", winnerDisplayName);
            return;
        }
        log.info("winner {} not in render distance for fireworks (chime still played)", winnerDisplayName);
    }

    /**
     * Schedule the host NPC to despawn after {@code delayMs}. Used for the
     * abrupt forfeit case; see {@link #scheduleHostExit} for the natural
     * match-end farewell sequence.
     */
    private void scheduleDespawnHost(long delayMs)
    {
        new java.util.Timer(true).schedule(new java.util.TimerTask()
        {
            @Override
            public void run()
            {
                hostNpcRenderer.requestDespawn();
            }
        }, delayMs);
    }

    /**
     * Multi-stage host exit: wave goodbye, walk a few tiles off the arena,
     * then despawn. Looks much more grounded than an in-place wave + vanish.
     *
     * Timing (relative to call):
     *   t=0      cheer/shrug reaction already playing (started by caller)
     *   t=4.5s   wave goodbye
     *   t=6.0s   clear the speech bubble + start walk-out toward
     *            {@link #walkOutDestinationFor}
     *   t=~8.4s  despawn (walk complete)
     *
     * We bumped the wave delay from 3s -> 4.5s and explicitly clear the
     * bubble at walk start: the bubble is anchored to the original host
     * tile (not the moving NPC), so a lingering line would visually float
     * at an empty square as the host strolls away. Clearing it the moment
     * the host's feet move keeps the staging consistent.
     */
    private void scheduleHostExit(Domain.WorldPoint hostTile)
    {
        final long waveDelay = 4_500;
        final long waveDuration = 1_500;
        final long walkStart = waveDelay + waveDuration;     // 6000

        scheduleAfter(waveDelay, () -> hostNpcRenderer.playReaction(ANIM_WAVE, waveDuration));
        if (hostTile != null)
        {
            Domain.WorldPoint exit = walkInOriginFor(hostTile); // same tile as walk-in
            // Despawn runs as the walk-out arrival callback, so it fires the
            // moment the host actually reaches the exit tile — no Timer race
            // with the walk's true duration (which is tile-paced and can vary
            // by up to one game tick depending on alignment with GameTick).
            scheduleAfter(walkStart, () ->
            {
                speechOverlay.clear();
                hostNpcRenderer.walkTo(exit, () -> hostNpcRenderer.requestDespawn());
            });
        }
        else
        {
            // No host tile (defensive) — just clear text + despawn after the wave.
            scheduleAfter(walkStart + 500, () ->
            {
                speechOverlay.clear();
                hostNpcRenderer.requestDespawn();
            });
        }
    }

    /**
     * Pick the spawn/exit tile relative to the host's resting tile. We use a
     * fixed offset south of the host. Doesn't check collision — if a wall
     * happens to be in the way the host walks through it visually, but since
     * RuneLiteObjects don't interact with terrain pathing this is harmless.
     */
    private static Domain.WorldPoint walkInOriginFor(Domain.WorldPoint hostTile)
    {
        return new Domain.WorldPoint(hostTile.x, hostTile.y - WALK_OFFSET_TILES, hostTile.plane);
    }

    /** Daemon Timer convenience for scheduling a Runnable after a delay. */
    private static void scheduleAfter(long delayMs, Runnable r)
    {
        new java.util.Timer(true).schedule(new java.util.TimerTask()
        {
            @Override
            public void run() { r.run(); }
        }, delayMs);
    }

    /**
     * Append a chat line styled to look like the host NPC speaking. Uses
     * GAMEMESSAGE channel so it appears in the player's main chat tab and
     * is reviewable in history.
     *
     * Must be called on the client thread (the message handlers above already
     * wrap in {@link ClientThread#invoke}).
     */
    private void handleBanter(Messages.BanterPayload p)
    {
        clientThread.invoke(() ->
        {
            MatchSession session = activeMatch;
            if (session == null || !p.matchId.equals(session.matchId)) return;
            if (!"struggling".equalsIgnoreCase(p.kind)) return;
            // Map the named "struggling" player to (player, opponent) for line
            // interpolation. The host taunts the strugger by encouraging the
            // opponent — so {player}=who's struggling, {opponent}=the other.
            String strugglerNorm = com.runetrivia.util.NameUtil.normalize(p.displayName);
            String playerDisplay;
            String opponentDisplay;
            if (strugglerNorm.equals(session.myNormalized))
            {
                playerDisplay = session.myDisplayName;
                opponentDisplay = session.opponentDisplayName;
            }
            else if (strugglerNorm.equals(session.opponentNormalized))
            {
                playerDisplay = session.opponentDisplayName;
                opponentDisplay = session.myDisplayName;
            }
            else
            {
                log.debug("BANTER for unknown player {} (mine={}, opponent={})",
                    p.displayName, session.myDisplayName, session.opponentDisplayName);
                return;
            }
            Map<String, String> vars = new HashMap<>();
            vars.put("player", playerDisplay);
            vars.put("opponent", opponentDisplay);
            sayCategory("playerStruggling", vars);
            // Host laughs at the struggle — teasing energy.
            hostNpcRenderer.playReaction(ANIM_LAUGH, 2_000);
            log.info("banter struggling: {} -> taunt opponent {}", playerDisplay, opponentDisplay);
        });
    }

    /**
     * Server says someone in this match was caught using the wiki. Apply
     * the clown-suit override for the announced duration and have the host
     * deliver a mocking line. The actual forfeit + match teardown arrives
     * shortly after as MATCH_COMPLETED with reason=forfeit; this handler
     * just owns the shame ceremony.
     */
    private void handleShamePlayer(Messages.ShamePlayerPayload p)
    {
        clientThread.invoke(() ->
        {
            outfitOverride.shame(p.cheaterDisplayName, p.durationMs);
            Map<String, String> vars = new HashMap<>();
            vars.put("cheater", p.cheaterDisplayName);
            sayCategory("cheaterShamed", vars);
            log.info("SHAME applied to {} for {}ms", p.cheaterDisplayName, p.durationMs);
        });
    }

    /** Active host's display name (or a generic fallback if no match is active). */
    private String hostName()
    {
        MatchSession session = activeMatch;
        return (session != null && session.host != null && session.host.displayName != null)
            ? session.host.displayName
            : "Trivia Host";
    }

    /**
     * Convenience: pick a line from the named category for the current host
     * and route it through {@link #hostSay(String)}. If the host or category
     * isn't found, silently no-ops (and logs at debug).
     */
    private void sayCategory(String category, Map<String, String> vars)
    {
        String line = hostLines.pick(hostName(), category, vars);
        if (line == null || line.isEmpty())
        {
            log.debug("no host line for category={} host={}", category, hostName());
            return;
        }
        hostSay(line);
    }

    /**
     * Emit a host line: render in the speech bubble overlay (immersive) AND
     * append a styled copy to game chat (reviewable in chat history). Multi-line
     * input (\n-delimited) is collapsed to a single chat line but preserved in
     * the bubble's word-wrap.
     */
    private void hostSay(String line)
    {
        hostSay(line, null);
    }

    /**
     * Same as {@link #hostSay(String)} but fires {@code onInstalled} the moment
     * the line actually becomes the visible overhead text in the speech overlay.
     * Used to gate side effects (banner reveal, sound effects, animations) so
     * they coincide with the host's verbal delivery instead of racing ahead.
     *
     * The callback fires on the overlay's render thread (Swing EDT), so any
     * client-side game-state mutation must be re-routed through
     * {@code clientThread.invoke}.
     */
    private void hostSay(String line, Runnable onInstalled)
    {
        String chatLine = line.replace("\n", " ");
        String formatted = new ChatMessageBuilder()
            .append(ChatColorType.HIGHLIGHT)
            .append(hostName() + ": ")
            .append(ChatColorType.NORMAL)
            .append(chatLine)
            .build();
        client.addChatMessage(ChatMessageType.GAMEMESSAGE, "", formatted, null);
        speechOverlay.say(line, onInstalled);
    }

    /** Repaint the side-panel match view from the current activeMatch snapshot. */
    private void renderActiveMatchPanel()
    {
        MatchSession session = activeMatch;
        if (panel == null) return;
        if (session == null)
        {
            panel.renderMatch(null);
            return;
        }
        String header;
        switch (session.getState())
        {
            case STAGING:
                header = session.isLocalReady()
                    ? "Ready — waiting for opponent"
                    : "Step into the arena around the host";
                break;
            case IN_PROGRESS:
                int qi = session.getCurrentQuestionIndex();
                header = qi >= 0 ? "Round " + (qi + 1) + " of 5" : "Get ready…";
                break;
            case COMPLETE:
            default:
                header = "Match complete";
                break;
        }

        String leftStatus = "";
        String rightStatus = "";
        if (session.getState() == MatchSession.State.IN_PROGRESS
            && session.getLastCorrectDisplay() != null)
        {
            if (session.getLastCorrectDisplay().equalsIgnoreCase(session.myDisplayName))
            {
                leftStatus = "correct";
            }
            else if (session.getLastCorrectDisplay().equalsIgnoreCase(session.opponentDisplayName))
            {
                rightStatus = "correct";
            }
        }

        int leftScore = session.getScores().getOrDefault(session.myDisplayName, 0);
        int rightScore = session.getScores().getOrDefault(session.opponentDisplayName, 0);

        panel.renderMatch(new TriviaPanel.MatchView(
            header,
            session.myDisplayName, leftScore, leftStatus,
            session.opponentDisplayName, rightScore, rightStatus));
    }

    /**
     * Clear the active-match panel a few seconds after completion. We compare
     * matchId so that if a new match has begun in the meantime, we don't
     * clobber it.
     */
    private void scheduleClearActiveMatch(String matchId)
    {
        new java.util.Timer(true).schedule(new java.util.TimerTask()
        {
            @Override
            public void run()
            {
                clientThread.invoke(() ->
                {
                    MatchSession s = activeMatch;
                    if (s != null && matchId.equals(s.matchId))
                    {
                        activeMatch = null;
                        renderActiveMatchPanel();
                    }
                });
            }
            // 7s: lets the full cheer (3s) + wave (1.5s) + walk-out (2s)
            // sequence in scheduleHostExit complete before we clear the panel.
        }, 7_000);
    }

    private static String humanReason(String reason)
    {
        if (reason == null) return "unknown";
        switch (reason)
        {
            case "accepted": return "accepted";
            case "mutual_accept": return "both challenged each other — match starting";
            case "declined": return "declined by target";
            case "expired": return "no response (expired)";
            case "cancelled": return "cancelled";
            case "out_of_range": return "target is too far away";
            case "target_busy": return "target is in another match";
            case "target_refusing": return "target isn't accepting challenges";
            case "target_offline": return "target isn't online";
            default: return reason;
        }
    }

    // -- Helpers -----------------------------------------------------------

    private void startWebsocket()
    {
        Player me = client.getLocalPlayer();
        if (me == null || me.getName() == null)
        {
            return;
        }
        wsClient.updateDisplayName(me.getName());
        wsClient.start(config.backendUrl(), me.getName(), config.acceptingChallenges());
    }

    private void refreshMatchHistory()
    {
        Request req = new Request.Builder().url(config.apiUrl() + "/api/matches?limit=5").build();
        httpClient.newCall(req).enqueue(new Callback()
        {
            @Override
            public void onFailure(Call call, IOException e)
            {
                if (panel != null)
                {
                    panel.renderHistory(List.of());
                }
            }

            @Override
            public void onResponse(Call call, Response response) throws IOException
            {
                try (Response r = response)
                {
                    if (!r.isSuccessful() || r.body() == null)
                    {
                        return;
                    }
                    String body = r.body().string();
                    com.google.gson.JsonArray arr = gson.fromJson(body, com.google.gson.JsonArray.class);
                    List<String> rows = new ArrayList<>();
                    for (JsonElement el : arr)
                    {
                        com.google.gson.JsonObject obj = el.getAsJsonObject();
                        String a = obj.getAsJsonArray("opponents").get(0).getAsString();
                        String b = obj.getAsJsonArray("opponents").get(1).getAsString();
                        String winner = obj.get("winnerDisplayName").isJsonNull() ? null : obj.get("winnerDisplayName").getAsString();
                        rows.add(a + " vs " + b + " — " + (winner == null ? "draw" : winner + " wins"));
                    }
                    if (panel != null)
                    {
                        panel.renderHistory(rows);
                    }
                }
            }
        });
    }

}

package com.runetrivia;

import net.runelite.client.config.Config;
import net.runelite.client.config.ConfigGroup;
import net.runelite.client.config.ConfigItem;
import net.runelite.client.config.ConfigSection;

@ConfigGroup("runetrivia")
public interface RuneTriviaConfig extends Config
{
    /**
     * How the host NPC's speech is rendered.
     *   OVERHEAD_PIXEL — yellow OSRS pixel font with black drop shadow,
     *                    floating above the NPC's head. No bubble. Matches
     *                    authentic overhead chat style.
     *   BUBBLE         — rounded white panel with a tail (the original
     *                    Phase 5 style). Useful for longer lines that need
     *                    to wrap inside a defined area.
     */
    enum HostSpeechStyle
    {
        OVERHEAD_PIXEL,
        BUBBLE
    }

    // ====================================================================
    // Section headers — order here = order in the config panel.
