package com.runetrivia.shame;

import java.util.HashMap;
import java.util.Map;
import javax.inject.Inject;
import javax.inject.Singleton;
import lombok.extern.slf4j.Slf4j;
import net.runelite.api.Client;
import net.runelite.api.GameState;
import net.runelite.api.Player;
import net.runelite.api.PlayerComposition;
import net.runelite.api.events.GameStateChanged;
import net.runelite.api.events.PlayerSpawned;
import net.runelite.api.kit.KitType;
import net.runelite.client.callback.ClientThread;
import net.runelite.client.eventbus.Subscribe;
import com.runetrivia.util.NameUtil;

/**
 * Client-side player appearance override. Currently used exclusively by
 * the anti-cheat shame flow: when the server sends SHAME_PLAYER, the
 * named player is poof'd, dressed in the modern Clown outfit for a
 * fixed duration, then poof'd again and restored to their real
 * equipment.
 *
 * <h3>How it works</h3>
 *
 * RuneLite exposes {@link PlayerComposition#getEquipmentIds()} as a
 * mutable int[]. Each slot index (see {@link KitType#getIndex()}) holds
 * either an item ID (offset by +512) or a kit ID (offset by +256).
 * Mutating the array and calling {@link PlayerComposition#setHash()}
 * triggers the engine to recompute the model on the next frame.
 *
 * <h3>What players see</h3>
 *
 * <ul>
 *   <li>The local client renders the override. <strong>Other RuneTrivia
 *       plugin users also see it</strong> because they receive the same
 *       SHAME_PLAYER broadcast.</li>
 *   <li>Random observers who don't have the plugin see the cheater's
 *       real equipment. Cheating context is preserved within the
 *       trivia community.</li>
 *   <li>The cheater themselves sees the clown suit on their own model.
 *       Their own plugin renders the override too — they can't ignore
 *       the punishment.</li>
 * </ul>
 *
 * <h3>Persistence + cleanup</h3>
 *
 * Overrides expire after their announced duration (typically 10s, set
 * by the server). {@link #tick()} should be called once per game tick
 * from the plugin's existing GameTick subscriber to expire stale
 * entries — expiry restores original equipment and plays the
 * dispersal poof. {@link #onPlayerSpawned(PlayerSpawned)} re-applies
 * the override when a shamed player walks back into render distance.
 */
@Singleton
@Slf4j
public class PlayerOutfitOverride
{
    // Modern Clown outfit (2018 Halloween event). IDs verified via
    // individual wiki pages — see https://oldschool.runescape.wiki/w/Clown_outfit.
    private static final int CLOWN_MASK = 22689;       // head
    private static final int CLOWN_BOW_TIE = 22692;    // amulet/neck
    private static final int CLOWN_GOWN = 22695;       // torso
    private static final int CLOWN_TROUSERS = 22698;   // legs
    private static final int CLOWN_SHOES = 22701;      // boots

    /**
     * Offset added to a real item ID when writing into a PlayerComposition
     * equipmentIds slot. The encoding is:
     *   0           = nothing
     *   256-2047    = kit (kitId + 256), used for hair, skin, beard, etc.
     *   >= 2048     = item (itemId + 2048), used for actual equipment
     *
     * Sourced from fashionscape-plugin's SwapManager.java + PlayerComposition.ITEM_OFFSET.
     * I originally used 512 here, which is in the kit-ID range and caused
     * the engine to interpret our writes as nonsense kit values, rendering
     * the wrong items or nothing at all.
     */
    private static final int EQUIPMENT_ID_OFFSET = 2048;

    /**
     * Graphic ID for the "poof" smoke effect. The same dispersal puff
     * that fires when a familiar / pet is dismissed. Plays both when
     * the clown suit appears (entry) and when it's removed (exit), so
     * the transformation reads as a punchy magic effect rather than a
     * silent gear swap. If this ID isn't quite right in-game, swap to
     * 1294 (smoke) or 444 (burst) as alternatives.
     */
    private static final int POOF_GRAPHIC_ID = 86;

    private final Client client;
    private final ClientThread clientThread;

    /** Per-shame state we need to track until expiry. */
    private static final class Shame
    {
        final long deadline;
        /** Snapshot of equipmentIds before the override was applied. Null if we never saw the player. */
        int[] originalEquipment;

        Shame(long deadline)
        {
            this.deadline = deadline;
        }
    }

    /** Normalized display name -> shame state. */
    private final Map<String, Shame> shamed = new HashMap<>();

    @Inject
    public PlayerOutfitOverride(Client client, ClientThread clientThread)
    {
        this.client = client;
        this.clientThread = clientThread;
    }

    /**
     * Begin shaming the named player. Idempotent — calling twice with the
     * same name extends the deadline to the latter of the two.
     *
     * Thread: safe from any thread; queues onto the client thread before
     * touching player models.
     */
    public void shame(String displayName, long durationMs)
    {
        if (displayName == null || displayName.isEmpty()) return;
        final String norm = NameUtil.normalize(displayName);
        final long deadline = System.currentTimeMillis() + Math.max(durationMs, 1_000);
        synchronized (shamed)
        {
            Shame existing = shamed.get(norm);
            if (existing == null || existing.deadline < deadline)
            {
                shamed.put(norm, new Shame(deadline));
            }
        }
        clientThread.invoke(() -> applyToVisiblePlayer(norm));
        log.debug("shame applied to {} until {}", displayName, deadline);
    }

    /**
     * Call once per GameTick from the plugin's existing tick subscriber.
     * Expires stale entries — playing a dispersal poof and restoring the
     * player's pre-shame equipment from the snapshot we saved on apply.
     */
    public void tick()
    {
        final long now = System.currentTimeMillis();
        // Take a snapshot of expiring entries under lock, then process
        // them outside the lock since the restore touches the client.
        Map<String, Shame> expiring = new HashMap<>();
        synchronized (shamed)
        {
            shamed.entrySet().removeIf(e ->
            {
                if (e.getValue().deadline <= now)
                {
                    expiring.put(e.getKey(), e.getValue());
                    return true;
                }
                return false;
            });
        }
        if (expiring.isEmpty()) return;
        clientThread.invoke(() ->
        {
            for (Map.Entry<String, Shame> e : expiring.entrySet())
            {
                restoreVisiblePlayer(e.getKey(), e.getValue());
            }
        });
    }

    /**
     * Re-apply the override whenever a shamed player enters render range.
     * Without this, walking out of view and back drops the clown suit
     * because the engine rebuilds the PlayerComposition from scratch.
     *
     * Subscribe wired by the main plugin so we get DI'd into the event bus.
     */
    @Subscribe
    public void onPlayerSpawned(PlayerSpawned event)
    {
        Player p = event.getPlayer();
        if (p == null || p.getName() == null) return;
        String norm = NameUtil.normalize(p.getName());
        Shame s;
        synchronized (shamed)
        {
            s = shamed.get(norm);
            if (s == null) return;
        }
        // No poof on re-spawn — only the initial shame triggers the effect.
        applyTo(p, s, false);
    }

    /**
     * Clear all shame state on logout / login screen. Prevents stale
     * overrides from a previous session leaking into a new one. We don't
     * try to restore — the player will reappear with fresh server data.
     */
    @Subscribe
    public void onGameStateChanged(GameStateChanged event)
    {
        if (event.getGameState() == GameState.LOGIN_SCREEN
            || event.getGameState() == GameState.HOPPING)
        {
            synchronized (shamed) { shamed.clear(); }
        }
    }

    // -- Internals ---------------------------------------------------------

    private void applyToVisiblePlayer(String normalizedName)
    {
        Shame s;
        synchronized (shamed) { s = shamed.get(normalizedName); }
        if (s == null) return;
        for (Player p : client.getPlayers())
        {
            if (p == null || p.getName() == null) continue;
            if (NameUtil.normalize(p.getName()).equals(normalizedName))
            {
                applyTo(p, s, true);
                return;
            }
        }
        // Player not currently visible — onPlayerSpawned will catch them
        // when they enter render range (without the poof, which is fine).
    }

    private void restoreVisiblePlayer(String normalizedName, Shame s)
    {
        for (Player p : client.getPlayers())
        {
            if (p == null || p.getName() == null) continue;
            if (NameUtil.normalize(p.getName()).equals(normalizedName))
            {
                playPoof(p);
                if (s.originalEquipment == null)
                {
                    log.warn("restore for {}: no original equipment snapshot; can't restore", p.getName());
                    return;
                }
                PlayerComposition pc = p.getPlayerComposition();
                if (pc == null)
                {
                    log.warn("restore for {}: PlayerComposition is null", p.getName());
                    return;
                }
                int[] eq = pc.getEquipmentIds();
                if (eq == null || eq.length < s.originalEquipment.length)
                {
                    log.warn("restore for {}: equipmentIds null or too short", p.getName());
                    return;
                }
                System.arraycopy(s.originalEquipment, 0, eq, 0, s.originalEquipment.length);
                pc.setHash();
                log.info("clown override restored for {}", p.getName());
                return;
            }
        }
        log.warn("restore for {}: player not found in scene; engine should rebuild on next spawn",
            normalizedName);
    }

    private void applyTo(Player p, Shame s, boolean playEntryPoof)
    {
        PlayerComposition pc = p.getPlayerComposition();
        if (pc == null) return;
        int[] eq = pc.getEquipmentIds();
        if (eq == null) return;

        // Save the original equipment exactly once, so on expiry we can
        // restore the player's real appearance instead of leaving them in
        // a half-clown state.
        if (s.originalEquipment == null)
        {
            s.originalEquipment = eq.clone();
        }

        eq[KitType.HEAD.getIndex()] = CLOWN_MASK + EQUIPMENT_ID_OFFSET;
        eq[KitType.AMULET.getIndex()] = CLOWN_BOW_TIE + EQUIPMENT_ID_OFFSET;
        eq[KitType.TORSO.getIndex()] = CLOWN_GOWN + EQUIPMENT_ID_OFFSET;
        eq[KitType.LEGS.getIndex()] = CLOWN_TROUSERS + EQUIPMENT_ID_OFFSET;
        eq[KitType.BOOTS.getIndex()] = CLOWN_SHOES + EQUIPMENT_ID_OFFSET;
        // Clear weapon and shield so the clown isn't holding a whip.
        eq[KitType.WEAPON.getIndex()] = 0;
        eq[KitType.SHIELD.getIndex()] = 0;
        // Clear kit slots that would otherwise poke through the clown
        // gear. Normally OSRS hides these automatically when a full
        // helm / body / etc. is equipped (via item-data flags), but
        // when we mutate equipmentIds directly we bypass that logic,
        // so we have to clear them manually. Restore puts them back
        // via the originalEquipment snapshot.
        //
        // HANDS is intentionally NOT cleared — the clown outfit has no
        // gloves item, so zeroing HANDS leaves the player with stumps.
        // The kit's hands render fine at the wrist where the gown ends.
        eq[KitType.HAIR.getIndex()] = 0;   // hair (was poking out the mask)
        eq[KitType.JAW.getIndex()] = 0;    // facial hair
        eq[KitType.ARMS.getIndex()] = 0;   // arm-kit (covered by gown)
        pc.setHash();
        log.info("clown override applied to {} (entryPoof={})", p.getName(), playEntryPoof);

        if (playEntryPoof)
        {
            playPoof(p);
        }
    }

    /**
     * Play the dispersal poof spot-anim on a player. Same effect that
     * fires when a familiar / pet is dismissed.
     *
     * Like the equipment override, this is client-side rendering only —
     * only RuneTrivia plugin users in render range see it. The cheater
     * sees it on their own model since their plugin renders it too.
     */
    private void playPoof(Player p)
    {
        p.setGraphic(POOF_GRAPHIC_ID);
        p.setSpotAnimFrame(0);
    }
}

package com.runetrivia.ui;

import java.awt.Color;
import java.awt.Dimension;
import java.util.function.Supplier;
import javax.inject.Inject;
import javax.inject.Singleton;
import net.runelite.client.ui.overlay.OverlayPanel;
import net.runelite.client.ui.overlay.OverlayPosition;
import net.runelite.client.ui.overlay.OverlayPriority;
import net.runelite.client.ui.overlay.components.LineComponent;
import net.runelite.client.ui.overlay.components.TitleComponent;

/**
 * Floating in-game banner shown when an opponent has challenged the local
 * player to a trivia match. Communicates the challenger's name + a brief
 * instruction to open the side panel (the side panel still owns the
 * Accept/Decline buttons themselves — the banner is a visibility cue,
 * not a duplicate action surface).
 *
 * The plugin supplies the challenger's display name via a Supplier. Returning
 * null hides the overlay. Auto-clears the moment CHALLENGE_RESOLVED arrives
 * (the plugin resets the supplier's source).
 *
 * Positioned TOP_CENTER like the question banner — they don't clash because
 * incoming challenges only fire pre-match, and the question banner only
 * renders during IN_PROGRESS.
 */
@Singleton
public class IncomingChallengeBanner extends OverlayPanel
{
    /** Returns the challenger's display name, or null when nothing should render. */
    private Supplier<String> challengerSupplier = () -> null;

    @Inject
    public IncomingChallengeBanner()
    {
        setPosition(OverlayPosition.TOP_CENTER);
        setPriority(OverlayPriority.HIGH);
        panelComponent.setPreferredSize(new Dimension(280, 0));
    }

    public void setChallengerSupplier(Supplier<String> s)
    {
        this.challengerSupplier = s == null ? () -> null : s;
    }

    @Override
    public Dimension render(java.awt.Graphics2D graphics)
    {
        String name = challengerSupplier.get();
        if (name == null || name.isEmpty()) return null;

        panelComponent.getChildren().clear();
        panelComponent.getChildren().add(TitleComponent.builder()
            .text("Trivia challenge")
            .color(new Color(0xE6AC2A))
            .build());

        panelComponent.getChildren().add(LineComponent.builder()
            .left(name + " has challenged you!")
            .build());

        panelComponent.getChildren().add(LineComponent.builder()
            .left("Check the side panel to accept.")
            .leftColor(new Color(0xCCCCCC))
            .build());

        panelComponent.getChildren().add(LineComponent.builder()
            .left("or type ::accept / ::decline")
            .leftColor(new Color(0x888888))
            .build());

        return super.render(graphics);
    }
}

package com.runetrivia.ui;

import com.runetrivia.RuneTriviaConfig;
import com.runetrivia.match.MatchSession;
import com.runetrivia.net.messages.Domain;
import java.awt.BasicStroke;
import java.awt.Color;
import java.awt.Dimension;
import java.awt.Font;
import java.awt.FontMetrics;
import java.awt.Graphics2D;
import java.awt.Polygon;
import java.awt.RenderingHints;
import java.awt.geom.RoundRectangle2D;
import java.util.ArrayList;
import java.util.List;
import java.util.function.Supplier;
import javax.inject.Inject;
import javax.inject.Singleton;
import net.runelite.api.Client;
import net.runelite.api.Perspective;
import net.runelite.api.Point;
import net.runelite.api.coords.LocalPoint;
import net.runelite.api.coords.WorldPoint;
import net.runelite.client.ui.FontManager;
import net.runelite.client.ui.overlay.Overlay;
import net.runelite.client.ui.overlay.OverlayLayer;
import net.runelite.client.ui.overlay.OverlayPosition;
import net.runelite.client.ui.overlay.OverlayPriority;

/**
 * OSRS-style speech bubble for the trivia host. Renders a rounded white
 * panel with a downward tail above the host NPC's tile, displaying the
 * most recent line for {@link #DEFAULT_HOLD_MS}.
 *
 * Behaviour (per Phase 5 design call):
 *   * {@link #say(String)} replaces the current bubble immediately.
 *   * A {@link #MIN_HOLD_MS} minimum-hold window protects against flashing:
 *     if a second say() arrives while the previous line is still inside the
 *     min-hold window, the new line is queued and installed once the window
 *     elapses.
 *   * Bubble auto-clears after {@link #DEFAULT_HOLD_MS} from install.
 *   * Lines support \n for hard newlines. Long lines wrap at MAX_WIDTH_PX.
 *
 * The overlay never holds plugin state directly — it polls a
 * Supplier&lt;MatchSession&gt; for the host tile each frame.
 */
@Singleton
public class HostSpeechOverlay extends Overlay
{
    /**
     * Minimum time a line must remain visible before it can be replaced.
     * This is the single knob that paces the host's speech — events that
     * fire close together (walk-arrival welcome + MATCH_STARTED getReady +
     * QUESTION_DELIVERED intro often land within ~1s of each other on the
     * wire) are queued by say(), then promoted one at a time once each
     * predecessor has displayed for at least MIN_HOLD_MS. Set this to the
     * smallest comfortable reading time for a short line.
     */
    private static final long MIN_HOLD_MS = 2_500;
    /** Default time a line stays on screen when nothing replaces it (~8 game ticks). */
    private static final long DEFAULT_HOLD_MS = 4_800;
    /** Maximum bubble interior width before we wrap text. */
    private static final int MAX_WIDTH_PX = 260;
    /** Padding inside the bubble. */
    private static final int PAD_X = 10;
    private static final int PAD_Y = 6;
    /** Height above the host tile (in game units) where the bubble points. */
    private static final int ANCHOR_HEIGHT = 280;
    /** Tail (the little triangle at the bottom pointing down to the speaker). */
    private static final int TAIL_W = 12;
    private static final int TAIL_H = 8;

    private static final Color BUBBLE_FILL = new Color(0xFA, 0xF3, 0xDE, 240);
    private static final Color BUBBLE_BORDER = new Color(0x3A, 0x2F, 0x24);
    private static final Color BUBBLE_SHADOW = new Color(0x00, 0x00, 0x00, 90);
    private static final Color TEXT_COLOR = new Color(0x1A, 0x16, 0x12);

    // -- Overhead-pixel style (no bubble, OSRS chat-style) ----------------
    /** Yellow body of an authentic OSRS overhead line. */
    private static final Color PIXEL_TEXT = Color.YELLOW;
    /** Solid black drop-shadow, 1px down + right, matching engine overhead. */
    private static final Color PIXEL_SHADOW = Color.BLACK;
    /** Anchor height for the pixel style — slightly higher than the bubble. */
    private static final int PIXEL_ANCHOR_HEIGHT = 220;
    /** Max width for the pixel style's wrap (no border, can be wider). */
    private static final int PIXEL_MAX_WIDTH_PX = 320;

    private final Client client;
    private final RuneTriviaConfig config;
    private Supplier<MatchSession> sessionSupplier = () -> null;

    /** Currently displayed line, or null if nothing showing. */
    private volatile String currentLine;
    private volatile long currentStart;
    private volatile long expiresAt;
    /** Earliest moment we may install a new line on top of the current one. */
    private volatile long minHoldUntil;
    /**
     * FIFO queue of lines waiting for the current line's min-hold to expire.
     * Each entry has an optional onInstalled callback that fires when the
     * line actually becomes the visible line — this is how the plugin
     * synchronizes things like the question banner reveal with the moment
     * the host starts saying the question intro.
     */
    private final java.util.Deque<Pending> queue = new java.util.concurrent.ConcurrentLinkedDeque<>();

    private static final class Pending
    {
        final String line;
        final Runnable onInstalled;
        Pending(String line, Runnable onInstalled) { this.line = line; this.onInstalled = onInstalled; }
    }

    @Inject
    public HostSpeechOverlay(Client client, RuneTriviaConfig config)
    {
        this.client = client;
        this.config = config;
        setPosition(OverlayPosition.DYNAMIC);
        // Above the tile overlay but below the question banner / UI.
        setLayer(OverlayLayer.ABOVE_SCENE);
        setPriority(OverlayPriority.HIGH);
    }

    public void setSessionSupplier(Supplier<MatchSession> s)
    {
        this.sessionSupplier = s == null ? () -> null : s;
    }

    /**
     * Show a new line. If a previous line is still within its minimum-hold
     * window, the new line is queued and installs the moment the window
     * elapses. Lines are visible for {@link #DEFAULT_HOLD_MS}.
     */
    public void say(String line)
    {
        say(line, null);
    }

    /**
     * Same as {@link #say(String)} but fires {@code onInstalled} on the
     * render thread (Swing EDT, since overlays render there) the moment
     * the line actually becomes visible — either immediately if no queue
     * is ahead, or after the min-hold window of every preceding line.
     *
     * Used to synchronize side effects (question banner reveal, sound
     * effects, reaction animations) with the speech they accompany. If
     * the line is dropped via {@link #clear()} before installing, the
     * callback is silently discarded.
     */
    public void say(String line, Runnable onInstalled)
    {
        if (line == null || line.isEmpty()) return;
        long now = System.currentTimeMillis();
        if (now < minHoldUntil && currentLine != null)
        {
            queue.add(new Pending(line, onInstalled));
            return;
        }
        installLine(line, onInstalled, now);
    }

    private void installLine(String line, Runnable onInstalled, long now)
    {
        currentLine = line;
        currentStart = now;
        expiresAt = now + DEFAULT_HOLD_MS;
        minHoldUntil = now + MIN_HOLD_MS;
        if (onInstalled != null)
        {
            try { onInstalled.run(); }
            catch (Exception ignored) { /* installed-callback should not break rendering */ }
        }
    }

    /** Clear immediately. Called on match end / disconnect. Queued callbacks are dropped. */
    public void clear()
    {
        currentLine = null;
        queue.clear();
        expiresAt = 0;
        minHoldUntil = 0;
    }

    @Override
    public Dimension render(Graphics2D g)
    {
        MatchSession s = sessionSupplier.get();
        if (s == null) { clear(); return null; }
        if (s.host == null || s.host.tile == null) return null;

        long now = System.currentTimeMillis();
        // Promote the next queued line if the current one's min-hold has
        // elapsed. We promote at most one per render frame — installLine
        // resets minHoldUntil, so the *next* queued line waits another
        // MIN_HOLD_MS before its turn.
        if (currentLine != null && now >= minHoldUntil && !queue.isEmpty())
        {
            Pending next = queue.poll();
            installLine(next.line, next.onInstalled, now);
        }
        // Expire the current line. If something else is queued the loop
        // above will pick it up on the next frame.
        if (currentLine != null && now > expiresAt)
        {
            currentLine = null;
            // If a queue entry is sitting behind an expired line, install it
            // right away so we don't have a blank frame.
            if (!queue.isEmpty())
            {
                Pending next = queue.poll();
                installLine(next.line, next.onInstalled, now);
            }
        }
        if (currentLine == null) return null;

        RuneTriviaConfig.HostSpeechStyle style = config.hostSpeechStyle();
        if (style == RuneTriviaConfig.HostSpeechStyle.OVERHEAD_PIXEL)
        {
            renderPixelOverhead(g, s.host.tile, currentLine);
        }
        else
        {
            renderBubble(g, s.host.tile, currentLine);
        }
        return null;
    }

    // -- drawing -----------------------------------------------------------

    /**
     * Authentic OSRS overhead-chat style: yellow pixel font with a 1px
     * black drop shadow, centered above the host tile. No bubble, no
     * border. Looks indistinguishable from a real NPC overhead line —
     * because it uses the same FontManager.getRunescapeFont() the engine
     * does. Multi-line lines (\n) and long lines (auto-wrapped at
     * PIXEL_MAX_WIDTH_PX) stack vertically.
     */
    private void renderPixelOverhead(Graphics2D g, Domain.WorldPoint hostTile, String text)
    {
        WorldPoint world = new WorldPoint(hostTile.x, hostTile.y, hostTile.plane);
        LocalPoint lp = LocalPoint.fromWorld(client, world);
        if (lp == null) return;
        Point anchor = Perspective.getCanvasTextLocation(client, g, lp, "", PIXEL_ANCHOR_HEIGHT);
        if (anchor == null) return;

        Font prevFont = g.getFont();
        // Bold variant matches authentic OSRS overhead chat — the regular
        // RunescapeFont is the thinner UI font used for menus, not the one
        // the engine renders over players' heads.
        Font pixelFont = FontManager.getRunescapeBoldFont();
        // The bitmap font is designed to be pixel-perfect; disable AA so
        // it doesn't get smeared.
        Object prevTAA = g.getRenderingHint(RenderingHints.KEY_TEXT_ANTIALIASING);
        g.setRenderingHint(RenderingHints.KEY_TEXT_ANTIALIASING, RenderingHints.VALUE_TEXT_ANTIALIAS_OFF);
        g.setFont(pixelFont);
        FontMetrics fm = g.getFontMetrics();

        List<String> lines = wrapText(fm, text, PIXEL_MAX_WIDTH_PX);
        int lineHeight = fm.getHeight();
        // Stack lines upward from the anchor so the bottom line sits at
        // the anchor (consistent with where the bubble's tail tip would
        // have been).
        int baselineY = anchor.getY() - (lines.size() - 1) * lineHeight;
        for (String line : lines)
        {
            int width = fm.stringWidth(line);
            int x = anchor.getX() - width / 2;
            g.setColor(PIXEL_SHADOW);
            g.drawString(line, x + 1, baselineY + 1);
            g.setColor(PIXEL_TEXT);
            g.drawString(line, x, baselineY);
            baselineY += lineHeight;
        }

        g.setFont(prevFont);
        if (prevTAA != null) g.setRenderingHint(RenderingHints.KEY_TEXT_ANTIALIASING, prevTAA);
    }

    private void renderBubble(Graphics2D g, Domain.WorldPoint hostTile, String text)
    {
        WorldPoint world = new WorldPoint(hostTile.x, hostTile.y, hostTile.plane);
        LocalPoint lp = LocalPoint.fromWorld(client, world);
        if (lp == null) return;
        Point anchor = Perspective.getCanvasTextLocation(client, g, lp, "", ANCHOR_HEIGHT);
        if (anchor == null) return;

        // Enable AA for the rounded rect + text.
        Object prevAA = g.getRenderingHint(RenderingHints.KEY_ANTIALIASING);
        Object prevTAA = g.getRenderingHint(RenderingHints.KEY_TEXT_ANTIALIASING);
        g.setRenderingHint(RenderingHints.KEY_ANTIALIASING, RenderingHints.VALUE_ANTIALIAS_ON);
        g.setRenderingHint(RenderingHints.KEY_TEXT_ANTIALIASING, RenderingHints.VALUE_TEXT_ANTIALIAS_ON);

        Font prevFont = g.getFont();
        Font bubbleFont = prevFont.deriveFont(Font.PLAIN, 13f);
        g.setFont(bubbleFont);
        FontMetrics fm = g.getFontMetrics();

        List<String> lines = wrapText(fm, text, MAX_WIDTH_PX);
        int textWidth = 0;
        for (String line : lines)
        {
            int w = fm.stringWidth(line);
            if (w > textWidth) textWidth = w;
        }
        int lineHeight = fm.getHeight();
        int bubbleW = textWidth + PAD_X * 2;
        int bubbleH = lineHeight * lines.size() + PAD_Y * 2;

        int anchorX = anchor.getX();
        int anchorY = anchor.getY();
        // The bubble sits so its tail tip points at the anchor.
        int bubbleX = anchorX - bubbleW / 2;
        int bubbleY = anchorY - bubbleH - TAIL_H;

        // Drop shadow first.
        g.setColor(BUBBLE_SHADOW);
        g.fill(new RoundRectangle2D.Float(bubbleX + 2, bubbleY + 3, bubbleW, bubbleH, 14, 14));

        // Body.
        g.setColor(BUBBLE_FILL);
        g.fill(new RoundRectangle2D.Float(bubbleX, bubbleY, bubbleW, bubbleH, 14, 14));
        g.setColor(BUBBLE_BORDER);
        g.setStroke(new BasicStroke(1.5f));
        g.draw(new RoundRectangle2D.Float(bubbleX, bubbleY, bubbleW, bubbleH, 14, 14));

        // Tail: a small triangle pointing down to the anchor.
        Polygon tail = new Polygon();
        int tailBaseY = bubbleY + bubbleH;
        tail.addPoint(anchorX - TAIL_W / 2, tailBaseY);
        tail.addPoint(anchorX + TAIL_W / 2, tailBaseY);
        tail.addPoint(anchorX, tailBaseY + TAIL_H);
        g.setColor(BUBBLE_FILL);
        g.fillPolygon(tail);
        g.setColor(BUBBLE_BORDER);
        // Draw only the two slanted edges of the tail (skip the top edge to blend
        // with the bubble's bottom border).
        g.drawLine(anchorX - TAIL_W / 2, tailBaseY, anchorX, tailBaseY + TAIL_H);
        g.drawLine(anchorX + TAIL_W / 2, tailBaseY, anchorX, tailBaseY + TAIL_H);

        // Text.
        g.setColor(TEXT_COLOR);
        int textX = bubbleX + PAD_X;
        int textY = bubbleY + PAD_Y + fm.getAscent();
        for (String line : lines)
        {
            g.drawString(line, textX, textY);
            textY += lineHeight;
        }

        // Restore graphics state.
        g.setFont(prevFont);
        if (prevAA != null) g.setRenderingHint(RenderingHints.KEY_ANTIALIASING, prevAA);
        if (prevTAA != null) g.setRenderingHint(RenderingHints.KEY_TEXT_ANTIALIASING, prevTAA);
    }

    /**
     * Greedy word-wrap. Respects explicit \n. Lines that don't fit even after
     * splitting (very long single words) are emitted whole rather than mid-word
     * truncated — they'll just overhang the bubble width slightly.
     */
    static List<String> wrapText(FontMetrics fm, String text, int maxWidthPx)
    {
        List<String> out = new ArrayList<>();
        for (String paragraph : text.split("\\n"))
        {
            if (paragraph.isEmpty())
            {
                out.add("");
                continue;
            }
            StringBuilder current = new StringBuilder();
            for (String word : paragraph.split(" "))
            {
                String candidate = current.length() == 0 ? word : current + " " + word;
                if (fm.stringWidth(candidate) <= maxWidthPx)
                {
                    current.setLength(0);
                    current.append(candidate);
                }
                else
                {
                    if (current.length() > 0) out.add(current.toString());
                    current.setLength(0);
                    current.append(word);
                }
            }
            if (current.length() > 0) out.add(current.toString());
        }
        return out;
    }
}

package com.runetrivia.ui;

import com.runetrivia.match.MatchSession;
import java.awt.Color;
import java.awt.Dimension;
import java.util.function.Supplier;
import javax.inject.Inject;
import javax.inject.Singleton;
import net.runelite.client.ui.overlay.OverlayPanel;
import net.runelite.client.ui.overlay.OverlayPosition;
import net.runelite.client.ui.overlay.OverlayPriority;
import net.runelite.client.ui.overlay.components.LineComponent;
import net.runelite.client.ui.overlay.components.TitleComponent;

/**
 * Slim, non-blocking in-game overlay shown only while a question is active
 * (between QUESTION_DELIVERED and QUESTION_RESOLVED). Renders prompt + scores
 * + countdown. The plugin core supplies a snapshot via a Supplier so this
 * overlay never holds a direct reference to mutable plugin state.
 */
@Singleton
public class TriviaQuestionOverlay extends OverlayPanel
{
    /** Returns the live active match, or null when nothing should render. */
    private Supplier<MatchSession> sessionSupplier = () -> null;

    @Inject
    public TriviaQuestionOverlay()
    {
        setPosition(OverlayPosition.TOP_CENTER);
        setPriority(OverlayPriority.HIGH);
        panelComponent.setPreferredSize(new Dimension(280, 0));
    }

    public void setSessionSupplier(Supplier<MatchSession> s)
    {
        this.sessionSupplier = s == null ? () -> null : s;
    }

    @Override
    public Dimension render(java.awt.Graphics2D graphics)
    {
        MatchSession s = sessionSupplier.get();
        if (s == null) return null;
        if (s.getState() != MatchSession.State.IN_PROGRESS) return null;
        if (!s.isQuestionActive()) return null;
        String prompt = s.getCurrentPrompt();
        if (prompt == null || prompt.isEmpty()) return null;

        long now = System.currentTimeMillis();
        long remainingMs = Math.max(0, s.getCurrentDeadline() - now);
        int seconds = (int) Math.ceil(remainingMs / 1000.0);

        panelComponent.getChildren().clear();
        panelComponent.getChildren().add(TitleComponent.builder()
            .text("Q" + (s.getCurrentQuestionIndex() + 1) + " — type in chat")
            .color(new Color(0xE6AC2A))
            .build());

        panelComponent.getChildren().add(LineComponent.builder()
            .left(prompt)
            .build());

        panelComponent.getChildren().add(LineComponent.builder()
            .left(s.myDisplayName + ": " + s.getScores().getOrDefault(s.myDisplayName, 0))
            .right(s.opponentDisplayName + ": " + s.getScores().getOrDefault(s.opponentDisplayName, 0))
            .build());

        Color timerColor = seconds <= 3 ? new Color(0xC23A3A) : new Color(0xCCCCCC);
        panelComponent.getChildren().add(LineComponent.builder()
            .left("Time")
            .right(seconds + "s")
            .rightColor(timerColor)
            .build());

        return super.render(graphics);
    }
}

package com.runetrivia.ui;

import com.runetrivia.net.TriviaWsClient;
import java.awt.BorderLayout;
import java.awt.Color;
import java.awt.Component;
import java.awt.Dimension;
import java.awt.FlowLayout;
import java.awt.Font;
import java.awt.GridLayout;
import java.awt.event.ActionEvent;
import javax.swing.BorderFactory;
import javax.swing.Box;
import javax.swing.BoxLayout;
import javax.swing.JButton;
import javax.swing.JCheckBox;
import javax.swing.JLabel;
import javax.swing.JPanel;
import javax.swing.JTextField;
import javax.swing.SwingUtilities;
import lombok.Setter;
import net.runelite.client.ui.ColorScheme;
import net.runelite.client.ui.PluginPanel;

/**
 * Side panel: connection indicator, manual challenge entry, accepting-challenges
 * toggle, pending challenge prompt, recent match history.
 *
 * The panel doesn't talk to the WebSocket directly — it fires callbacks and
 * the plugin core wires those to TriviaWsClient.
 */
public class TriviaPanel extends PluginPanel
{
    public interface Callbacks
    {
        /** User typed a name and clicked "Challenge". */
        void onManualChallenge(String targetDisplayName);

        /** User toggled the accepting-challenges checkbox. */
        void onAcceptingToggled(boolean accepting);

        /** User clicked Accept / Decline on a pending challenge. */
        void onChallengeResponse(String challengeId, boolean accept);

        /** User clicked the Forfeit button on an active match. */
        void onForfeitMatch();
    }

    private final JLabel statusLabel = new JLabel("Disconnected");
    private final JLabel statusDot = new JLabel("●");
    private final JTextField nameField = new JTextField(12);
    private final JButton challengeBtn = new JButton("Challenge");
    private final JCheckBox acceptingBox = new JCheckBox("Accept incoming challenges", true);
    private final JPanel pendingPanel = new JPanel();
    private final JPanel outgoingPanel = new JPanel();
    private final JPanel matchPanel = new JPanel();
    private final JPanel historyPanel = new JPanel();

    @Setter
    private Callbacks callbacks;

    private String pendingChallengeId;

    public TriviaPanel()
    {
        setLayout(new BorderLayout());
        setBorder(BorderFactory.createEmptyBorder(8, 8, 8, 8));

        JPanel root = new JPanel();
        root.setLayout(new BoxLayout(root, BoxLayout.Y_AXIS));

        root.add(buildHeader());
        root.add(Box.createVerticalStrut(12));
        root.add(buildConnectionRow());
        root.add(Box.createVerticalStrut(8));
        root.add(buildAcceptingRow());
        root.add(Box.createVerticalStrut(12));
        root.add(buildChallengeRow());
        root.add(Box.createVerticalStrut(12));
        root.add(buildOutgoingPanel());
        root.add(Box.createVerticalStrut(12));
        root.add(buildPendingPanel());
        root.add(Box.createVerticalStrut(12));
        root.add(buildMatchPanel());
        root.add(Box.createVerticalStrut(12));
        root.add(buildHistoryPanel());

        add(root, BorderLayout.NORTH);

        setStatus(TriviaWsClient.Status.DISCONNECTED);
        renderPending(null, null);
        renderOutgoing(null, null);
        renderMatch(null);
    }

    private JPanel buildHeader()
    {
        JLabel title = new JLabel("RuneTrivia");
        title.setFont(title.getFont().deriveFont(Font.BOLD, 16f));
        JPanel p = new JPanel(new FlowLayout(FlowLayout.LEFT, 0, 0));
        p.add(title);
        alignLeft(p);
        return p;
    }

    private JPanel buildConnectionRow()
    {
        JPanel p = new JPanel(new FlowLayout(FlowLayout.LEFT, 4, 0));
        statusDot.setFont(statusDot.getFont().deriveFont(Font.BOLD, 18f));
        p.add(statusDot);
        p.add(statusLabel);
        alignLeft(p);
        return p;
    }

    private JPanel buildAcceptingRow()
    {
        acceptingBox.addActionListener((ActionEvent e) ->
        {
            if (callbacks != null)
            {
                callbacks.onAcceptingToggled(acceptingBox.isSelected());
            }
        });
        JPanel p = new JPanel(new FlowLayout(FlowLayout.LEFT, 0, 0));
        p.add(acceptingBox);
        alignLeft(p);
        return p;
    }

    private JPanel buildChallengeRow()
    {
        challengeBtn.addActionListener((ActionEvent e) ->
        {
            String name = nameField.getText().trim();
            if (!name.isEmpty() && callbacks != null)
            {
                callbacks.onManualChallenge(name);
                nameField.setText("");
            }
        });
        JPanel p = new JPanel();
        p.setLayout(new BoxLayout(p, BoxLayout.Y_AXIS));
        JLabel l = new JLabel("Challenge by name:");
        alignLeft(l);
        p.add(l);
        JPanel row = new JPanel(new FlowLayout(FlowLayout.LEFT, 4, 0));
        row.add(nameField);
        row.add(challengeBtn);
        // BoxLayout Y_AXIS uses the LARGEST child alignmentX as the layout
        // baseline. Without explicitly left-aligning `row` (default 0.5f
        // CENTER), the label's 0.0f LEFT_ALIGNMENT gets resolved against
        // a center baseline and ends up visibly indented. Left-align both.
        alignLeft(row);
        p.add(row);
        alignLeft(p);
        return p;
    }

    private JPanel buildPendingPanel()
    {
        pendingPanel.setLayout(new BoxLayout(pendingPanel, BoxLayout.Y_AXIS));
        pendingPanel.setBorder(BorderFactory.createTitledBorder("Incoming challenge"));
        alignLeft(pendingPanel);
        return pendingPanel;
    }

    private JPanel buildOutgoingPanel()
    {
        outgoingPanel.setLayout(new BoxLayout(outgoingPanel, BoxLayout.Y_AXIS));
        outgoingPanel.setBorder(BorderFactory.createTitledBorder("Outgoing challenge"));
        alignLeft(outgoingPanel);
        return outgoingPanel;
    }

    private JPanel buildMatchPanel()
    {
        matchPanel.setLayout(new BoxLayout(matchPanel, BoxLayout.Y_AXIS));
        matchPanel.setBorder(BorderFactory.createTitledBorder("Active match"));
        alignLeft(matchPanel);
        return matchPanel;
    }

    private JPanel buildHistoryPanel()
    {
        historyPanel.setLayout(new GridLayout(0, 1, 0, 2));
        historyPanel.setBorder(BorderFactory.createTitledBorder("Recent matches"));
        JLabel empty = new JLabel("No matches yet.");
        empty.setForeground(ColorScheme.LIGHT_GRAY_COLOR);
        historyPanel.add(empty);
        alignLeft(historyPanel);
        return historyPanel;
    }

    private static void alignLeft(Component c)
    {
        if (c instanceof JComponentEx)
        {
            ((JComponentEx) c).setAlignmentX(Component.LEFT_ALIGNMENT);
        }
        else if (c instanceof JPanel)
        {
            ((JPanel) c).setAlignmentX(Component.LEFT_ALIGNMENT);
        }
        else if (c instanceof JLabel)
        {
            ((JLabel) c).setAlignmentX(Component.LEFT_ALIGNMENT);
        }
    }

    // Marker for the alignLeft helper above when we want to accept any JComponent.
    private interface JComponentEx
    {
        void setAlignmentX(float f);
    }

    // -- Public API --------------------------------------------------------

    public void setStatus(TriviaWsClient.Status s)
    {
        SwingUtilities.invokeLater(() ->
        {
            switch (s)
            {
                case CONNECTED:
                    statusLabel.setText("Connected");
                    statusDot.setForeground(new Color(0x55B05B));
                    break;
                case CONNECTING:
                    statusLabel.setText("Connecting…");
                    statusDot.setForeground(new Color(0xE6AC2A));
                    break;
                case DISCONNECTED:
                default:
                    statusLabel.setText("Disconnected");
                    statusDot.setForeground(new Color(0xC23A3A));
                    break;
            }
        });
    }

    /**
     * Render an incoming challenge prompt. Pass null to clear.
     */
    public void renderPending(String challengeId, String fromDisplayName)
    {
        SwingUtilities.invokeLater(() ->
        {
            pendingPanel.removeAll();
            pendingChallengeId = challengeId;
            if (challengeId == null)
            {
                JLabel empty = new JLabel("No pending challenges.");
                empty.setForeground(ColorScheme.LIGHT_GRAY_COLOR);
                empty.setAlignmentX(Component.LEFT_ALIGNMENT);
                pendingPanel.add(empty);
            }
            else
            {
                JLabel from = new JLabel("From: " + fromDisplayName);
                from.setAlignmentX(Component.LEFT_ALIGNMENT);
                pendingPanel.add(from);
                JPanel row = new JPanel(new FlowLayout(FlowLayout.LEFT, 4, 0));
                JButton accept = new JButton("Accept");
                JButton decline = new JButton("Decline");
                accept.addActionListener(e ->
                {
                    if (callbacks != null)
                    {
                        callbacks.onChallengeResponse(challengeId, true);
                    }
                });
                decline.addActionListener(e ->
                {
                    if (callbacks != null)
                    {
                        callbacks.onChallengeResponse(challengeId, false);
                    }
                });
                row.add(accept);
                row.add(decline);
                row.setAlignmentX(Component.LEFT_ALIGNMENT);
                pendingPanel.add(row);
            }
            pendingPanel.revalidate();
            pendingPanel.repaint();
        });
    }

    /**
     * Render outgoing-challenge state. Pass a status message (e.g. "Challenge
     * sent to Bob — waiting for response", "Challenge cancelled: target was
     * offline", or "Challenge accepted!"). Pass null to clear.
     */
    public void renderOutgoing(String targetDisplayName, String statusMessage)
    {
        SwingUtilities.invokeLater(() ->
        {
            outgoingPanel.removeAll();
            if (statusMessage == null)
            {
                JLabel empty = new JLabel("No outgoing challenges.");
                empty.setForeground(ColorScheme.LIGHT_GRAY_COLOR);
                empty.setAlignmentX(Component.LEFT_ALIGNMENT);
                outgoingPanel.add(empty);
            }
            else
            {
                if (targetDisplayName != null)
                {
                    JLabel target = new JLabel("To: " + targetDisplayName);
                    target.setAlignmentX(Component.LEFT_ALIGNMENT);
                    outgoingPanel.add(target);
                }
                JLabel status = new JLabel(statusMessage);
                status.setAlignmentX(Component.LEFT_ALIGNMENT);
                outgoingPanel.add(status);
            }
            outgoingPanel.revalidate();
            outgoingPanel.repaint();
        });
    }

    /**
     * Snapshot of the active-match panel state. Null leftCorrect/rightCorrect
     * mean "no answer yet"; "" (empty) is treated the same as null. Non-empty
     * strings are rendered under the corresponding player's name.
     */
    public static final class MatchView
    {
        public final String header;
        public final String leftName;
        public final int leftScore;
        public final String leftStatus;
        public final String rightName;
        public final int rightScore;
        public final String rightStatus;

        public MatchView(
            String header,
            String leftName, int leftScore, String leftStatus,
            String rightName, int rightScore, String rightStatus)
        {
            this.header = header;
            this.leftName = leftName;
            this.leftScore = leftScore;
            this.leftStatus = leftStatus;
            this.rightName = rightName;
            this.rightScore = rightScore;
            this.rightStatus = rightStatus;
        }
    }

    /**
     * Render the active-match view. Pass null to hide it.
     */
    public void renderMatch(MatchView view)
    {
        SwingUtilities.invokeLater(() ->
        {
            matchPanel.removeAll();
            if (view == null)
            {
                JLabel empty = new JLabel("No active match.");
                empty.setForeground(ColorScheme.LIGHT_GRAY_COLOR);
                empty.setAlignmentX(Component.LEFT_ALIGNMENT);
                matchPanel.add(empty);
            }
            else
            {
                if (view.header != null && !view.header.isEmpty())
                {
                    JLabel h = new JLabel(view.header);
                    h.setFont(h.getFont().deriveFont(Font.BOLD));
                    h.setAlignmentX(Component.LEFT_ALIGNMENT);
                    matchPanel.add(h);
                    matchPanel.add(Box.createVerticalStrut(6));
                }
                appendContestant(view.leftName, view.leftScore, view.leftStatus);
                matchPanel.add(Box.createVerticalStrut(8));
                appendContestant(view.rightName, view.rightScore, view.rightStatus);
                // Forfeit button at the bottom of the active-match panel.
                // Confirmation dialog avoids accidental forfeit from a stray
                // click — the user has to confirm the abrupt match exit.
                matchPanel.add(Box.createVerticalStrut(10));
                JButton forfeit = new JButton("Forfeit match");
                forfeit.setAlignmentX(Component.LEFT_ALIGNMENT);
                forfeit.addActionListener(e ->
                {
                    int choice = javax.swing.JOptionPane.showConfirmDialog(
                        matchPanel,
                        "Forfeit the current match? Your opponent will be awarded the win.",
                        "Confirm forfeit",
                        javax.swing.JOptionPane.YES_NO_OPTION,
                        javax.swing.JOptionPane.WARNING_MESSAGE);
                    if (choice == javax.swing.JOptionPane.YES_OPTION && callbacks != null)
                    {
                        callbacks.onForfeitMatch();
                    }
                });
                matchPanel.add(forfeit);
            }
            matchPanel.revalidate();
            matchPanel.repaint();
        });
    }

    private void appendContestant(String name, int score, String status)
    {
        JLabel nameLabel = new JLabel(name + "  (" + score + ")");
        nameLabel.setAlignmentX(Component.LEFT_ALIGNMENT);
        // Subtle underline via a bottom-bordered panel.
        JPanel wrapper = new JPanel();
        wrapper.setLayout(new BoxLayout(wrapper, BoxLayout.Y_AXIS));
        wrapper.setBorder(BorderFactory.createMatteBorder(0, 0, 1, 0, ColorScheme.LIGHT_GRAY_COLOR));
        wrapper.add(nameLabel);
        wrapper.setAlignmentX(Component.LEFT_ALIGNMENT);
        matchPanel.add(wrapper);
        JLabel statusLabel = new JLabel(status == null || status.isEmpty() ? " " : status);
        if ("correct".equalsIgnoreCase(status))
        {
            statusLabel.setForeground(new Color(0x55B05B));
        }
        statusLabel.setAlignmentX(Component.LEFT_ALIGNMENT);
        matchPanel.add(statusLabel);
    }

    /**
     * Replace the match-history list. Pass entries shortest-first
     * (each line e.g. "Alice vs Bob — Alice wins").
     */
    public void renderHistory(java.util.List<String> entries)
    {
        SwingUtilities.invokeLater(() ->
        {
            historyPanel.removeAll();
            if (entries == null || entries.isEmpty())
            {
                JLabel empty = new JLabel("No matches yet.");
                empty.setForeground(ColorScheme.LIGHT_GRAY_COLOR);
                historyPanel.add(empty);
            }
            else
            {
                for (String s : entries)
                {
                    historyPanel.add(new JLabel(s));
                }
            }
            historyPanel.revalidate();
            historyPanel.repaint();
        });
    }

    public Dimension getPreferredSize()
    {
        return new Dimension(PluginPanel.PANEL_WIDTH, super.getPreferredSize().height);
    }

    public String getPendingChallengeId()
    {
        return pendingChallengeId;
    }

    public void setAcceptingChallenges(boolean accepting)
    {
        SwingUtilities.invokeLater(() -> acceptingBox.setSelected(accepting));
    }
}

package com.runetrivia.ui;

import com.runetrivia.RuneTriviaConfig;
import com.runetrivia.match.MatchSession;
import com.runetrivia.net.messages.Domain;
import java.awt.BasicStroke;
import java.awt.Color;
import java.awt.Dimension;
import java.awt.Font;
import java.awt.FontMetrics;
import java.awt.Graphics2D;
import java.awt.Polygon;
import java.awt.Stroke;
import java.util.function.Supplier;
import javax.inject.Inject;
import javax.inject.Singleton;
import net.runelite.api.Client;
import net.runelite.api.Perspective;
import net.runelite.api.Point;
import net.runelite.api.coords.LocalPoint;
import net.runelite.api.coords.WorldPoint;
import net.runelite.client.ui.overlay.Overlay;
import net.runelite.client.ui.overlay.OverlayLayer;
import net.runelite.client.ui.overlay.OverlayPosition;
import net.runelite.client.ui.overlay.OverlayPriority;

/**
 * Paints the arena: a (2*ARENA_RADIUS+1) square of tiles centered on the
 * host NPC's tile, plus the host name floating above the host tile. Players
 * step into this area during STAGING to auto-ready.
 *
 * The colors intensify during STAGING (to draw attention) and dim once the
 * match is in progress (so the play space is still visible but unobtrusive).
 */
@Singleton
public class ArenaTileOverlay extends Overlay
{
    private static final Stroke OUTLINE = new BasicStroke(2f);
    private static final Stroke OUTLINE_THIN = new BasicStroke(1f);

    private static final Color HOST_TILE = new Color(0xFF, 0xE0, 0x8A, 220);
    private static final Color ARENA_OUTLINE_STAGING = new Color(0xFF, 0xC8, 0x44, 200);
    private static final Color ARENA_FILL_STAGING = new Color(0xFF, 0xC8, 0x44, 40);

    // The destination arrow (yellow, blinking, both world + minimap) is now
    // driven by the engine's own hint-arrow system. See
    // RuneTriviaPlugin.updateHintArrow — that uses client.setHintArrow which
    // gives us the exact arrow Jagex uses in tutorials/quests, with native
    // world + minimap rendering for free.

    private final Client client;
    private final RuneTriviaConfig config;
    private Supplier<MatchSession> sessionSupplier = () -> null;

    @Inject
    public ArenaTileOverlay(Client client, RuneTriviaConfig config)
    {
        this.client = client;
        this.config = config;
        setPosition(OverlayPosition.DYNAMIC);
        setLayer(OverlayLayer.ABOVE_SCENE);
        setPriority(OverlayPriority.MED);
    }

    public void setSessionSupplier(Supplier<MatchSession> s)
    {
        this.sessionSupplier = s == null ? () -> null : s;
    }

    @Override
    public Dimension render(Graphics2D g)
    {
        MatchSession s = sessionSupplier.get();
        if (s == null) return null;
        if (s.getState() == MatchSession.State.COMPLETE) return null;
        if (s.host == null || s.host.tile == null) return null;

        Domain.WorldPoint center = s.host.tile;

        // Tile mat is config-gated (off by default — the host NPC + engine
        // hint arrow already communicate "go here" without breaking the
        // immersion of the surrounding world). Host name label below is
        // drawn in both states regardless.
        if (s.getState() == MatchSession.State.STAGING && config.showArenaTileMat())
        {
            int r = MatchSession.ARENA_RADIUS;
            for (int dx = -r; dx <= r; dx++)
            {
                for (int dy = -r; dy <= r; dy++)
                {
                    if (dx == 0 && dy == 0) continue;
                    drawTile(g, center.x + dx, center.y + dy, center.plane,
                        ARENA_OUTLINE_STAGING, ARENA_FILL_STAGING, false);
                }
            }
            drawTile(g, center.x, center.y, center.plane, HOST_TILE,
                new Color(HOST_TILE.getRed(), HOST_TILE.getGreen(), HOST_TILE.getBlue(), 60), true);
            // The waypoint arrow itself is driven by the engine's hint-arrow
            // system from RuneTriviaPlugin.updateHintArrow — nothing to draw
            // here. We just paint the tile mat to communicate the arena
            // boundary.
        }

        if (config.showHostLabel() && s.host.displayName != null && !s.host.displayName.isEmpty())
        {
            drawHostLabel(g, center, s.host.displayName);
        }
        return null;
    }

    private void drawTile(Graphics2D g, int worldX, int worldY, int plane,
                          Color outlineColor, Color fillColor, boolean thick)
    {
        WorldPoint world = new WorldPoint(worldX, worldY, plane);
        LocalPoint lp = LocalPoint.fromWorld(client, world);
        if (lp == null) return;
        Polygon poly = Perspective.getCanvasTilePoly(client, lp);
        if (poly == null) return;
        g.setStroke(thick ? OUTLINE : OUTLINE_THIN);
        g.setColor(fillColor);
        g.fillPolygon(poly);
        g.setColor(outlineColor);
        g.drawPolygon(poly);
    }

    private void drawHostLabel(Graphics2D g, Domain.WorldPoint wp, String name)
    {
        WorldPoint world = new WorldPoint(wp.x, wp.y, wp.plane);
        LocalPoint lp = LocalPoint.fromWorld(client, world);
        if (lp == null) return;
        // ~200 game units above the ground = roughly head-height for a 1-tile NPC.
        Point screen = Perspective.getCanvasTextLocation(client, g, lp, name, 200);
        if (screen == null) return;
        Font prev = g.getFont();
        g.setFont(prev.deriveFont(Font.BOLD, 13f));
        FontMetrics fm = g.getFontMetrics();
        int width = fm.stringWidth(name);
        int x = screen.getX() - width / 2;
        int y = screen.getY();
        g.setColor(Color.BLACK);
        g.drawString(name, x + 1, y + 1);
        g.setColor(new Color(0xFFE08A));
        g.drawString(name, x, y);
        g.setFont(prev);
    }
}

package com.runetrivia.net;

import com.google.gson.Gson;
import com.google.gson.JsonElement;
import com.google.gson.JsonObject;
import com.runetrivia.net.messages.Domain;
import com.runetrivia.net.messages.Messages;
import com.runetrivia.net.messages.Messages.Envelope;
import com.runetrivia.net.messages.Messages.HelloPayload;
import java.util.UUID;
import java.util.concurrent.ScheduledExecutorService;
import java.util.concurrent.ScheduledThreadPoolExecutor;
import java.util.concurrent.TimeUnit;
import java.util.concurrent.atomic.AtomicReference;
import javax.inject.Inject;
import lombok.extern.slf4j.Slf4j;
import okhttp3.OkHttpClient;
import okhttp3.Request;
import okhttp3.Response;
import okhttp3.WebSocket;
import okhttp3.WebSocketListener;
import okio.ByteString;

/**
 * WebSocket client for the RuneTrivia backend.
 * <ul>
 *   <li>Opens a persistent connection while the plugin is enabled
 *   <li>Sends HELLO on connect (with the local player's display name)
 *   <li>Heartbeats with PING every 20s; server is expected to reply PONG
 *   <li>Reconnects with exponential backoff on disconnect or error
 *   <li>Dispatches received messages to the supplied {@link Listener}
 * </ul>
 *
 * Threading: OkHttp fires listener callbacks on its own IO threads. We do
 * not marshal to the game/EDT thread here — that's the caller's job, since
 * different callers need different threads (panel = EDT, plugin core = game
 * thread for things that touch the client object).
 */
@Slf4j
public class TriviaWsClient
{
    public enum Status { DISCONNECTED, CONNECTING, CONNECTED }

    public interface Listener
    {
        /** Status transition. May fire on any thread. */
        void onStatusChange(Status status);

        /**
         * A parsed inbound envelope. payload is a Gson JsonElement; the listener
         * decides how to deserialize it based on `type`.
         */
        void onMessage(String type, String id, JsonElement payload);
    }

    private static final long HEARTBEAT_MS = 20_000;
    private static final long BACKOFF_INITIAL_MS = 1_000;
    private static final long BACKOFF_MAX_MS = 30_000;

    private final OkHttpClient http;
    private final Gson gson;
    private final ScheduledExecutorService scheduler;

    private final AtomicReference<WebSocket> socket = new AtomicReference<>();
    private final AtomicReference<Status> status = new AtomicReference<>(Status.DISCONNECTED);

    private volatile Listener listener;
    private volatile String url;
    private volatile String displayName;
    private volatile String pluginVersion = "0.0.1";
    private volatile boolean acceptingChallenges = true;
    private volatile boolean running = false;
    private long backoffMs = BACKOFF_INITIAL_MS;

    @Inject
    public TriviaWsClient(OkHttpClient http, Gson gson)
    {
        this.http = http;
        this.gson = gson;
        // Daemon so we don't block JVM shutdown.
        ScheduledThreadPoolExecutor exec = new ScheduledThreadPoolExecutor(1, r ->
        {
            Thread t = new Thread(r, "runetrivia-ws");
            t.setDaemon(true);
            return t;
        });
        exec.setRemoveOnCancelPolicy(true);
        this.scheduler = exec;
    }

    public void setListener(Listener listener)
    {
        this.listener = listener;
    }

    public Status getStatus()
    {
        return status.get();
    }

    public synchronized void start(String wsUrl, String displayName, boolean acceptingChallenges)
    {
        this.url = wsUrl;
        this.displayName = displayName;
        this.acceptingChallenges = acceptingChallenges;
        if (running)
        {
            return;
        }
        running = true;
        backoffMs = BACKOFF_INITIAL_MS;
        connect();
        scheduler.scheduleAtFixedRate(this::heartbeat, HEARTBEAT_MS, HEARTBEAT_MS, TimeUnit.MILLISECONDS);
    }

    public synchronized void stop()
    {
        running = false;
        WebSocket s = socket.getAndSet(null);
        if (s != null)
        {
            try
            {
                s.close(1000, "client_shutdown");
            }
            catch (Exception ignored)
            {
            }
        }
        setStatus(Status.DISCONNECTED);
    }

    /** Update the accepting-challenges flag and push a STATUS_UPDATE to the server (if connected). */
    public void updateAcceptingChallenges(boolean accepting)
    {
        this.acceptingChallenges = accepting;
        if (status.get() == Status.CONNECTED)
        {
            Messages.StatusUpdatePayload p = new Messages.StatusUpdatePayload();
            p.acceptingChallenges = accepting;
            send(Messages.TYPE_STATUS_UPDATE, p);
        }
    }

    public void updateDisplayName(String name)
    {
        this.displayName = name;
    }

    /**
     * Send a typed payload as a JSON envelope. No-op if not connected.
     */
    public <T> void send(String type, T payload)
    {
        WebSocket s = socket.get();
        if (s == null)
        {
            return;
        }
        Envelope<T> env = new Envelope<>();
        env.v = Domain.PROTOCOL_VERSION;
        env.type = type;
        env.id = UUID.randomUUID().toString();
        env.ts = System.currentTimeMillis();
        env.payload = payload;
        try
        {
            s.send(gson.toJson(env));
        }
        catch (Exception e)
        {
            log.warn("send {} failed", type, e);
        }
    }

    // -- internals ---------------------------------------------------------

    private void connect()
    {
        if (!running || url == null)
        {
            return;
        }
        setStatus(Status.CONNECTING);
        try
        {
            Request req = new Request.Builder().url(url).build();
            WebSocket s = http.newWebSocket(req, new Handler());
            socket.set(s);
        }
        catch (Exception e)
        {
            log.warn("failed to open WS to {}: {}", url, e.toString());
            scheduleReconnect();
        }
    }

    private void scheduleReconnect()
    {
        if (!running)
        {
            return;
        }
        setStatus(Status.DISCONNECTED);
        long delay = backoffMs;
        backoffMs = Math.min(backoffMs * 2, BACKOFF_MAX_MS);
        scheduler.schedule(this::connect, delay, TimeUnit.MILLISECONDS);
    }

    private void heartbeat()
    {
        if (status.get() != Status.CONNECTED)
        {
            return;
        }
        send(Messages.TYPE_PING, new Messages.PingPayload());
    }

    private void setStatus(Status s)
    {
        Status prev = status.getAndSet(s);
        if (prev != s)
        {
            Listener l = listener;
            if (l != null)
            {
                try
                {
                    l.onStatusChange(s);
                }
                catch (Exception e)
                {
                    log.warn("listener.onStatusChange threw", e);
                }
            }
        }
    }

    // -- handler -----------------------------------------------------------

    private class Handler extends WebSocketListener
    {
        @Override
        public void onOpen(WebSocket webSocket, Response response)
        {
            log.info("ws open: {}", url);
            backoffMs = BACKOFF_INITIAL_MS;
            setStatus(Status.CONNECTED);
            // Fire HELLO right away.
            HelloPayload hello = new HelloPayload();
            hello.displayName = displayName == null ? "Unknown" : displayName;
            hello.pluginVersion = pluginVersion;
            hello.acceptingChallenges = acceptingChallenges;
            send(Messages.TYPE_HELLO, hello);
        }

        @Override
        public void onMessage(WebSocket webSocket, String text)
        {
            try
            {
                JsonObject obj = gson.fromJson(text, JsonObject.class);
                String type = obj.has("type") ? obj.get("type").getAsString() : null;
                String id = obj.has("id") ? obj.get("id").getAsString() : null;
                JsonElement payload = obj.has("payload") ? obj.get("payload") : null;
                if (type == null)
                {
                    log.warn("dropping malformed frame: {}", text);
                    return;
                }
                Listener l = listener;
                if (l != null)
                {
                    l.onMessage(type, id, payload);
                }
            }
            catch (Exception e)
            {
                log.warn("failed to parse incoming frame: {}", text, e);
            }
        }

        @Override
        public void onMessage(WebSocket webSocket, ByteString bytes)
        {
            // We don't send binary frames; ignore.
        }

        @Override
        public void onClosing(WebSocket webSocket, int code, String reason)
        {
            log.info("ws closing: {} {}", code, reason);
        }

        @Override
        public void onClosed(WebSocket webSocket, int code, String reason)
        {
            log.info("ws closed: {} {}", code, reason);
            socket.compareAndSet(webSocket, null);
            scheduleReconnect();
        }

        @Override
        public void onFailure(WebSocket webSocket, Throwable t, Response response)
        {
            log.info("ws failure: {}", t.toString());
            socket.compareAndSet(webSocket, null);
            scheduleReconnect();
        }
    }
}

package com.runetrivia.net.messages;

/**
 * Shared structural types mirroring shared/src/domain.ts. Nested static
 * classes (rather than separate files) so the protocol surface lives in
 * two files — see also {@link Messages}.
 */
public final class Domain
{
    public static final int PROTOCOL_VERSION = 1;

    private Domain()
    {
    }

    /** Plain world-coord tuple. Mirrored manually because net.runelite.api.coords.WorldPoint isn't Gson-friendly. */
    public static final class WorldPoint
    {
        public int x;
        public int y;
        public int plane;

        public WorldPoint()
        {
        }

        public WorldPoint(int x, int y, int plane)
        {
            this.x = x;
            this.y = y;
            this.plane = plane;
        }
    }

    public static final class ArenaProposal
    {
        public int regionId;
        public WorldPoint npcTile;
        public WorldPoint challengerTile;
        public WorldPoint challengedTile;
    }

    public static final class HostNpc
    {
        public int npcId;
        public String displayName;
        public WorldPoint tile;
    }

    public static final class PerPlayerQuestionResult
    {
        public String text;
        public boolean correct;
        public Long responseMs;
    }
}

package com.runetrivia.net.messages;

import com.runetrivia.net.messages.Domain.ArenaProposal;
import com.runetrivia.net.messages.Domain.HostNpc;
import com.runetrivia.net.messages.Domain.PerPlayerQuestionResult;
import com.runetrivia.net.messages.Domain.WorldPoint;
import java.util.Map;

/**
 * Wire-protocol payloads, mirrored from shared/src/protocol.ts. Any change
 * to that file should be reflected here in the same commit.
 *
 * Convention: each payload is a plain Java class with public fields. Gson
 * populates them via reflection; no constructors or setters needed for
 * deserialization. We construct outbound payloads via the static helpers
 * at the bottom of this class.
 */
public final class Messages
{
    private Messages()
    {
    }

    // -- Envelope ----------------------------------------------------------

    /**
     * Generic message envelope. Outbound envelopes use the concrete payload
     * class as T; inbound envelopes start as Envelope<JsonElement> and the
     * dispatcher reparses payload based on the type field.
     */
    public static final class Envelope<T>
    {
        public int v;
        public String type;
        public String id;
        public long ts;
        public T payload;
    }

    // -- Message-type discriminators (mirrors shared/src/protocol.ts) -----

    public static final String TYPE_HELLO = "HELLO";
    public static final String TYPE_WELCOME = "WELCOME";
    public static final String TYPE_STATUS_UPDATE = "STATUS_UPDATE";
    public static final String TYPE_PING = "PING";
    public static final String TYPE_PONG = "PONG";
    public static final String TYPE_ERROR = "ERROR";

    public static final String TYPE_CHALLENGE_CREATE = "CHALLENGE_CREATE";
    public static final String TYPE_CHALLENGE_CREATED = "CHALLENGE_CREATED";
    public static final String TYPE_CHALLENGE_OFFERED = "CHALLENGE_OFFERED";
    public static final String TYPE_CHALLENGE_RESPOND = "CHALLENGE_RESPOND";
    public static final String TYPE_CHALLENGE_RESOLVED = "CHALLENGE_RESOLVED";
    public static final String TYPE_CHALLENGE_CANCEL = "CHALLENGE_CANCEL";

    public static final String TYPE_ARENA_STAGED = "ARENA_STAGED";
    public static final String TYPE_PLAYER_READY = "PLAYER_READY";

    public static final String TYPE_MATCH_STARTED = "MATCH_STARTED";
    public static final String TYPE_QUESTION_DELIVERED = "QUESTION_DELIVERED";
    public static final String TYPE_ANSWER_SUBMIT = "ANSWER_SUBMIT";
    public static final String TYPE_QUESTION_RESOLVED = "QUESTION_RESOLVED";
    public static final String TYPE_MATCH_COMPLETED = "MATCH_COMPLETED";
    public static final String TYPE_MATCH_FORFEIT = "MATCH_FORFEIT";
    public static final String TYPE_BANTER = "BANTER";

    // Anti-cheat (Phase 7)
    public static final String TYPE_WIKI_TRIGGERED = "WIKI_TRIGGERED";
    public static final String TYPE_SHAME_PLAYER = "SHAME_PLAYER";

    // -- Lifecycle payloads -----------------------------------------------

    public static final class HelloPayload
    {
        public String displayName;
        public String pluginVersion;
        public boolean acceptingChallenges;
    }

    public static final class WelcomePayload
    {
        public String serverVersion;
        public WelcomePayloadYou you;
    }

    public static final class WelcomePayloadYou
    {
        public String displayName;
    }

    public static final class StatusUpdatePayload
    {
        public boolean acceptingChallenges;
    }

    public static final class PingPayload
    {
    }

    public static final class PongPayload
    {
    }

    public static final class ErrorPayload
    {
        public String code;
        public String message;
        public String refId;
    }

    // -- Challenge payloads -----------------------------------------------

    public static final class ChallengeCreatePayload
    {
        public String targetDisplayName;
        public WorldPoint challengerLocation;
        public ArenaProposal proposedArena;
    }

    public static final class ChallengeCreatedPayload
    {
        public String challengeId;
        public String targetDisplayName;
        public long expiresAt;
    }

    public static final class ChallengeOfferedPayload
    {
        public String challengeId;
        public String fromDisplayName;
        public long expiresAt;
        public ArenaProposal proposedArena;
    }

    public static final class ChallengeRespondPayload
    {
        public String challengeId;
        public boolean accept;
    }

    public static final class ChallengeResolvedPayload
    {
        public String challengeId;
        public boolean accepted;
        public String matchId;
        public String reason;
    }

    public static final class ChallengeCancelPayload
    {
        public String challengeId;
    }

    // -- Staging payloads -------------------------------------------------

    public static final class ArenaStagedPayload
    {
        public String matchId;
        public int regionId;
        public HostNpc host;
        public Map<String, WorldPoint> tiles;
        public long stagingDeadline;
    }

    public static final class PlayerReadyPayload
    {
        public String matchId;
    }

    // -- Match payloads ---------------------------------------------------

    public static final class MatchStartedPayload
    {
        public String matchId;
        public String[] opponents;
        public int winTarget;
        public int maxQuestions;
        public String mode;
    }

    public static final class QuestionDeliveredPayload
    {
        public String matchId;
        public int questionIndex;
        public String prompt;
        public long deadline;
    }

    public static final class AnswerSubmitPayload
    {
        public String matchId;
        public int questionIndex;
        public String text;
    }

    public static final class QuestionResolvedPayload
    {
        public String matchId;
        public int questionIndex;
        public String canonicalAnswer;
        public Map<String, PerPlayerQuestionResult> results;
        public Map<String, Integer> scores;
    }

    public static final class MatchCompletedPayload
    {
        public String matchId;
        public String winnerDisplayName;
        public Map<String, Integer> finalScores;
        public int questionsPlayed;
        public String reason;
    }

    public static final class MatchForfeitPayload
    {
        public String matchId;
        public String reason;
    }

    /**
     * Server-emitted flavor message indicating a player's chat line was
     * recognised as frustration ("idk", "wtf", "???"). The plugin renders
     * a host overhead taunt encouraging the opponent.
     */
    public static final class BanterPayload
    {
        public String matchId;
        /** The display name of whoever triggered the banter. */
        public String displayName;
        /** Discriminator. v1: always "struggling". */
        public String kind;
    }

    // -- Anti-cheat payloads (Phase 7) ------------------------------------

    /**
     * Client → server. Fired the moment the plugin observes a wiki
     * interaction (RuneLite Wiki plugin menu action, in-game wiki search
     * widget load, ::wiki chat command) while this client is in an active
     * match. Zero-tolerance: server forfeits the cheater immediately.
     */
    public static final class WikiTriggeredPayload
    {
        public String matchId;
        /** "runelite_wiki_menu" | "in_game_wiki_widget" | "wiki_chat_command". */
        public String source;
    }

    /**
     * Server → client. Tells the receiving plugin to (a) override the named
     * player's PlayerComposition equipment to the clown suit for
     * durationMs, and (b) play the host's "cheaterShamed" dialogue line.
     * Sent to both opponents so the cheater also sees themselves dressed.
     */
    public static final class ShamePlayerPayload
    {
        public String matchId;
        public String cheaterDisplayName;
        public long durationMs;
    }
}

