		String areaStr = currentArea.isEmpty() ? "" : " | Area: " + currentArea;
		String entry = String.format("[%s] TASK RECEIVED: %s x%d%s | Tasks: %d | Points: %d",
			LocalDateTime.now().format(FORMATTER), monster, count, areaStr,
