		int n = plugin != null ? plugin.blocklist.size() : 0;
		if (n == 0)
		{
			hiddenCountLabel.setText(" ");
			hiddenCountLabel.setVisible(false);
		}
		else
		{
			hiddenCountLabel.setText(n + " item" + (n == 1 ? "" : "s") + " hidden — manage");
			hiddenCountLabel.setVisible(true);
