	private JButton buildHistorySortPill(String label, HistorySort mode)
	{
		JButton b = pillButton(label);
		applySortStyle(b, optHistorySort == mode);
		b.addActionListener(e ->
		{
			optHistorySort = mode;
			renderCompletedPositionsHistory();
		});
