	private static String ageSuffix(Integer ageMinutes)
	{
		if (ageMinutes == null)
		{
			return null;
		}
		if (ageMinutes < 1)
		{
			return "now";
		}
		if (ageMinutes < 60)
		{
			return ageMinutes + "m ago";
		}
		long h = ageMinutes / 60;
		return h + "h ago";
	}

