		TradeRecord bondA = merged(BOND, "Old school bond", true, 1, 15_174_000L, 1_000_000L);
		bondA.partial = false;
		TradeRecord bondB = merged(BOND, "Old school bond", true, 1, 15_174_000L, 1_000_001L);
