        }
        if (x == 33 && y == 38)
        {
            return "N4 (2)" + proc;
        }
        if (x == 34 && y == 39)
        {
            clog.addLine(MAIDEN_SCUFFED, "N4 (2)");
            return "N4 (2)" + proc;
        }
        //
        if (x == 21 && y == 20)
        {
            return "S1" + proc;
        }
        if (x == 22 && y == 19)
        {
            clog.addLine(MAIDEN_SCUFFED, "S1");
            return "S1" + proc;
        }
        if (x == 25 && y == 20)
        {
            return "S2" + proc;
        }
        if (x == 26 && y == 19)
        {
            clog.addLine(MAIDEN_SCUFFED, "S2");
            return "S2" + proc;
        }
        if (x == 29 && y == 20)
        {
            return "S3" + proc;
        }
        if (x == 30 && y == 19)
        {
            clog.addLine(MAIDEN_SCUFFED, "S3");
            return "S3" + proc;
        }
        if (x == 33 && y == 20)
        {
            return "S4 (1)" + proc;
        }
        if (x == 34 && y == 19)
        {
            clog.addLine(MAIDEN_SCUFFED, "S4 (1)");
            return "S4 (1)" + proc;
        }
        if (x == 33 && y == 22)
        {
            return "S4 (2)" + proc;
        }
        if (x == 34 && y == 21)
        {
            clog.addLine(MAIDEN_SCUFFED, "S4 (2)");
            return "S4 (2)" + proc;
        } else
        {
            return "Unknown";
