                        break;
                    case ACCURATE_NYLO_START:
                        nyloStartAccurate = true;
                        break;
                    case ACCURATE_NYLO_END:
                        nyloEndAccurate = true;
                        nyloTimeAccurate = nyloStartAccurate;
                        break;
