            String g1as = (g1a < g2a) ? better : g2a == g1a ? even : worse;
            String g1meds = (g1med < g2med) ? better : g2med == g1med ? even : worse;
            String g1mods = (g1mod < g2mod) ? better : g2mod == g1mod ? even : worse;
